#ifndef _BACKPROP_OPENCL_KERNEL_H_
#define _BACKPROP_OPENCL_KERNEL_H_

#include <CL/cl.h>

#define WIDTH 16
#define HEIGHT 16
#define ETA 0.3f
#define MOMENTUM 0.3f

__kernel void
bpnn_layerforward_ocl(__global float *input_cuda,
                      __global float *output_hidden_cuda,
                      __global float *input_hidden_cuda,
                      __global float *hidden_partial_sum,
                      int in,
                      int hid)
{
   int by = get_block_id_y();
   int tx = get_thread_id_x();
   int ty = get_thread_id_y();

   int index =  ( hid + 1 ) * HEIGHT * by + ( hid + 1 ) * ty + tx + 1 + ( hid + 1 );
   int index_in = HEIGHT * by + ty + 1;

   __local float input_node[HEIGHT];
   __local float weight_matrix[HEIGHT][WIDTH];

   if ( tx == 0 )
      input_node[ty] = input_cuda[index_in];

   barrier(CLK_LOCAL_MEM_FENCE);

   weight_matrix[ty][tx] = input_hidden_cuda[index];

   barrier(CLK_LOCAL_MEM_FENCE);

   weight_matrix[ty][tx] = weight_matrix[ty][tx] * input_node[ty];

   barrier(CLK_LOCAL_MEM_FENCE);

   for ( int i = 1 ; i <= log2((float)HEIGHT) ; i++){
       int power_two = 1 << i;
       if( ty % power_two == 0 )
           weight_matrix[ty][tx] = weight_matrix[ty][tx] + weight_matrix[ty + power_two/2][tx];
       barrier(CLK_LOCAL_MEM_FENCE);
   }

   input_hidden_cuda[index] = weight_matrix[ty][tx];

   barrier(CLK_LOCAL_MEM_FENCE);

   if ( tx == 0 ) {
       hidden_partial_sum[by * hid + ty] = weight_matrix[tx][ty];
   }
}

__kernel void
bpnn_adjust_weights_ocl(__global float * delta,
                        int hid,
                        __global float * ly,
                        int in,
                        __global float * w,
                        __global float * oldw)
{
   int by = get_block_id_y();
   int tx = get_thread_id_x();
   int ty = get_thread_id_y();

   int index =  ( hid + 1 ) * HEIGHT * by + ( hid + 1 ) * ty + tx + 1 + ( hid + 1 );
   int index_y = HEIGHT * by + ty + 1;
   int index_x = tx + 1;

   float new_dw = ((ETA * delta[index_x] * ly[index_y]) + (MOMENTUM * oldw[index]));
   w[index] += new_dw;
   oldw[index] = new_dw;

   barrier(CLK_LOCAL_MEM_FENCE);

   if (ty == 0 && by == 0){
       float bias_dw = ((ETA * delta[index_x]) + (MOMENTUM * oldw[index_x]));
       w[index_x] += bias_dw;
       oldw[index_x] = bias_dw;
   }
}

#endif

#define WIDTH 16
#define HEIGHT 16
#define ETA 0.3f
#define MOMENTUM 0.3f

__global__ void bpnn_layerforward_ocl(float *input_cuda,
                                      float *output_hidden_cuda,
                                      float *input_hidden_cuda,
                                      float *hidden_partial_sum,
                                      int in,
                                      int hid)
{
   int by = get_group_id(1);
   int tx = get_local_id(0);
   int ty = get_local_id(1);

   int index =  ( hid + 1 ) * HEIGHT * by + ( hid + 1 ) * ty + tx + 1 + ( hid + 1 );
   int index_in = HEIGHT * by + ty + 1;

   __local float input_node[HEIGHT];
   __local float weight_matrix[HEIGHT][WIDTH];

   if ( tx == 0 )
   input_node[ty] = input_cuda[index_in];

   barrier(CLK_LOCAL_MEM_FENCE);

   weight_matrix[ty][tx] = input_hidden_cuda[index];

   barrier(CLK_LOCAL_MEM_FENCE);

   weight_matrix[ty][tx] = weight_matrix[ty][tx] * input_node[ty];

   barrier(CLK_LOCAL_MEM_FENCE);

   int log2height = 0;
   int temp_h = HEIGHT;
   while (temp_h > 1) {
       temp_h >>= 1;
       log2height++;
   }

   for ( int i = 1 ; i <= log2height ; i++){
       int power_two = 1 << i;

       if( ty % power_two == 0 )
       weight_matrix[ty][tx] = weight_matrix[ty][tx] + weight_matrix[ty + power_two/2][tx];

       barrier(CLK_LOCAL_MEM_FENCE);
   }

   input_hidden_cuda[index] = weight_matrix[ty][tx];

   barrier(CLK_LOCAL_MEM_FENCE);

   if ( tx == 0 ) {
       hidden_partial_sum[by * hid + ty] = weight_matrix[tx][ty];
   }
}

__global__ void bpnn_adjust_weights_ocl(float * delta,
                                        int hid,
                                        float * ly,
                                        int in,
                                        float * w,
                                        float * oldw)
{
   int by = get_group_id(1);
   int tx = get_local_id(0);
   int ty = get_local_id(1);

   int index =  ( hid + 1 ) * HEIGHT * by + ( hid + 1 ) * ty + tx + 1 + ( hid + 1 );
   int index_y = HEIGHT * by + ty + 1;
   int index_x = tx + 1;

   float delta_val = delta[index_x];
   float ly_val = ly[index_y];
   float oldw_val = oldw[index];

   float new_dw = ((ETA * delta_val * ly_val) + (MOMENTUM * oldw_val));

   w[index] += new_dw;
   oldw[index] = new_dw;

   barrier(CLK_LOCAL_MEM_FENCE);

   if (ty == 0 && by == 0){
       float bias_oldw = oldw[index_x];
       float bias_new_dw = ((ETA * delta_val) + (MOMENTUM * bias_oldw));
       w[index_x] += bias_new_dw;
       oldw[index_x] = bias_new_dw;
   }
}

