template <typename T, int SIZE_X, int SIZE_Y, int BOUNDARY_X>
class TransformBuffer {
public:
    enum {
      VERTICAL_STRIDE = BOUNDARY_X + (SIZE_X / 2)
    };

  private:
    enum {
      SHM_BANKS = 16,
      BUFFER_SIZE = VERTICAL_STRIDE * SIZE_Y,
      PADDING = SHM_BANKS - ((BUFFER_SIZE + SHM_BANKS / 2) % SHM_BANKS),
      ODD_OFFSET = BUFFER_SIZE + PADDING,
    };

    T data[2 * BUFFER_SIZE + PADDING];

    template <typename FUNC>
    void horizontalStep(const int count, const int prevOffset, 
                                   const int midOffset, const int nextOffset,
                                   const FUNC & function, int threadIdx_x) {

      const int STEPS = count / SIZE_X;
      const int finalCount = count % SIZE_X; 
      const int finalOffset = count - finalCount;  

      for(int i = 0; i < STEPS; i++) {
        const T previous = data[prevOffset + i * SIZE_X + threadIdx_x];
        const T next     = data[nextOffset + i * SIZE_X + threadIdx_x];
        T & center       = data[midOffset  + i * SIZE_X + threadIdx_x];
        function(previous, center, next);
      }

      if(threadIdx_x < finalCount) {
        const T previous = data[prevOffset + finalOffset + threadIdx_x];
        const T next     = data[nextOffset + finalOffset + threadIdx_x];
        T & center = data[midOffset + finalOffset + threadIdx_x];
        function(previous, center, next);
      }
    }

  public:
    int getColumnOffset(int columnIndex) {
      columnIndex += BOUNDARY_X;             
      return columnIndex / 2                 
          + (columnIndex & 1) * ODD_OFFSET;  
    }

    T & operator[] (const int index) {
      return data[index];
    }

    template <typename FUNC>
    void forEachHorizontalEven(const int firstLine,
                                          const int numLines,
                                          const FUNC & func, int threadIdx_x) {
      const int count = numLines * VERTICAL_STRIDE - 1;
      const int centerOffset = firstLine * VERTICAL_STRIDE + 1;
      const int prevOffset = firstLine * VERTICAL_STRIDE + ODD_OFFSET;
      const int nextOffset = prevOffset + 1;
      horizontalStep(count, prevOffset, centerOffset, nextOffset, func, threadIdx_x);
    }

    template <typename FUNC>
    void forEachHorizontalOdd(const int firstLine,
                                         const int numLines,
                                         const FUNC & func, int threadIdx_x) {
      const int count = numLines * VERTICAL_STRIDE - 1;
      const int prevOffset = firstLine * VERTICAL_STRIDE;
      const int centerOffset = prevOffset + ODD_OFFSET;
      const int nextOffset = prevOffset + 1;
      horizontalStep(count, prevOffset, centerOffset, nextOffset, func, threadIdx_x);
    }

    template <typename F>
    void forEachVerticalEven(const int columnOffset, const F & f, int threadIdx_x) {
      if(SIZE_Y > 3) { 
        const int steps = SIZE_Y / 2 - 1;
        for(int i = 0; i < steps; i++) {
          const int row = 2 + i * 2;
          const T prev = data[columnOffset + (row - 1) * VERTICAL_STRIDE];
          const T next = data[columnOffset + (row + 1) * VERTICAL_STRIDE];
          T &curr = data[columnOffset + row * VERTICAL_STRIDE];
          f(prev, curr , next);
        }
      }
    }

    template <typename F>
    void forEachVerticalOdd(const int columnOffset, const F & f, int threadIdx_x) {
      const int steps = (SIZE_Y - 1) / 2;
      for(int i = 0; i < steps; i++) {
        const int row = i * 2 + 1;
        const T prev = data[columnOffset + (row - 1) * VERTICAL_STRIDE];
        const T next = data[columnOffset + (row + 1) * VERTICAL_STRIDE];
        T &curr = data[columnOffset + row * VERTICAL_STRIDE];
        f(prev, curr, next);
      }
    }

    void scaleHorizontal(const T evenScale, const T oddScale,
                                    const int firstLine, const int numLines, int threadIdx_x) {
      const int offset = firstLine * VERTICAL_STRIDE;
      const int count = numLines * VERTICAL_STRIDE;
      const int steps = count / SIZE_X;
      const int finalCount = count % SIZE_X;
      const int finalOffset = count - finalCount;

      for(int i = 0; i < steps; i++) {
        data[threadIdx_x + i * SIZE_X + offset] *= evenScale;
        data[threadIdx_x + i * SIZE_X + offset + ODD_OFFSET] *= oddScale;
      }

      if(threadIdx_x < finalCount) {
        data[threadIdx_x + finalOffset + offset] *= evenScale;
        data[threadIdx_x + finalOffset + offset + ODD_OFFSET] *= oddScale;
      }
    }

    void scaleVertical(const T evenScale, const T oddScale,
                                  const int columnOffset, const int numLines,
                                  const int firstLine) {
      for(int i = firstLine; i < (numLines + firstLine); i++) {
        if(i & 1) {
          data[columnOffset + i * VERTICAL_STRIDE] *= oddScale;
        } else {
          data[columnOffset + i * VERTICAL_STRIDE] *= evenScale;
        }
      }
    }
};

template <typename T, bool CHECKED>
class VerticalDWTPixelIO {
protected:
    int end;         
    int stride;      
    int initialize(const int sizeX, const int sizeY, int firstX, int firstY) {
      end = CHECKED ? (sizeY * sizeX + firstX) : 0;
      stride = sizeX;
      return firstX + sizeX * firstY;
    }
    static void mirror(int & d, const int & sizeD) {
      if(d >= sizeD) {
        d = 2 * sizeD - 2 - d;
      } else if(d < 0) {
        d = -d;
      }
    }
};

template <typename T, bool CHECKED>
class VerticalDWTPixelWriter : VerticalDWTPixelIO<T, CHECKED> {
  private:
    int next;   
  public:
    void init(const int sizeX, const int sizeY, int firstX, int firstY) {
      if(firstX < sizeX) {
        next = this->initialize(sizeX, sizeY, firstX, firstY);
      } else {
        this->end = 0;
        this->stride = 0;
        next = 0;
      }
    }
    void writeInto(T * const output, const T & value) {
      if((!CHECKED) || (next != this->end)) {
        output[next] = value;
        next += this->stride;
      }
    }
};

template <typename T, bool CHECKED>
class VerticalDWTPixelLoader : protected VerticalDWTPixelIO<const T, CHECKED> {
  private:
    int last;  
  public:
    void init(const int sizeX, const int sizeY, int firstX, int firstY) {
      this->mirror(firstX, sizeX);
      last = this->initialize(sizeX, sizeY, firstX, firstY) - sizeX;
    }
    void clear() {
      this->end = 0;
      this->stride = 0;
      this->last = 0;
    }
    T loadFrom(const T * const input) {
      last += this->stride;
      if(CHECKED && (last == this->end)) {
        last -= 2 * this->stride;
        this->stride = -this->stride; 
      }
      return input[last];
    }
};

template <typename T, bool CHECKED>
class VerticalDWTBandIO : protected VerticalDWTPixelIO<T, CHECKED> {
protected:
    int end;
    int strideHighToLow;
    int strideLowToHigh;
    int initialize(const int imageSizeX, const int imageSizeY, int firstX, int firstY) {
      int columnOffset = firstX / 2;
      int verticalStride;
      if(firstX & 1) {
        verticalStride = imageSizeX / 2;
        columnOffset += DIVANDRND(imageSizeX, 2) * DIVANDRND(imageSizeY, 2);
        strideLowToHigh = (imageSizeX * imageSizeY) / 2;
      } else {
        verticalStride = imageSizeX / 2 + (imageSizeX & 1);
        strideLowToHigh = DIVANDRND(imageSizeY, 2)  * imageSizeX;
      }
      strideHighToLow = verticalStride - strideLowToHigh;
      if(CHECKED) {
        end = columnOffset + (imageSizeY / 2) * verticalStride + (imageSizeY & 1) * strideLowToHigh;
      } else {
        end = 0;
      }
      return columnOffset + (firstY / 2) * verticalStride + (firstY & 1) * strideLowToHigh;
    }
};

template <typename T, bool CHECKED>
class VerticalDWTBandLoader : public VerticalDWTBandIO<const T, CHECKED> {
  private:
    int last;  
    T updateAndLoad(const T * const input, const int & stride) {
      last += stride;
      if(CHECKED && (last == this->end)) {
        last -= (this->strideLowToHigh + this->strideHighToLow);
        const int temp = this->strideLowToHigh;
        this->strideLowToHigh = -this->strideHighToLow;
        this->strideHighToLow = -temp;
      }
      return input[last];
    }
  public:
    void init(const int imageSizeX, const int imageSizeY, int firstX, const int firstY) {
      this->mirror(firstX, imageSizeX);
      last = this->initialize(imageSizeX, imageSizeY, firstX, firstY);
      last -= (firstY & 1) ? this->strideLowToHigh : this->strideHighToLow; 
    }
    void clear() {
      this->end = 0;
      this->strideHighToLow = 0;
      this->strideLowToHigh = 0;
      this->last = 0;
    }
    T loadLowFrom(const T * const input) {
      return updateAndLoad(input, this->strideHighToLow);
    }
    T loadHighFrom(const T * const input) {
      return updateAndLoad(input, this->strideLowToHigh);
    }
};

template <typename T, bool CHECKED>
class VerticalDWTBandWriter : public VerticalDWTBandIO<T, CHECKED> {
  private:
    int next;  
    int saveAndUpdate(T * const output, const T & item, const int & stride) {
      if((!CHECKED) || (next != this->end)) {
        output[next] = item;
        next += stride;
      } 
      return next;
    }
  public:
    void init(const int imageSizeX, const int imageSizeY, const int firstX, const int firstY) {
      if (firstX < imageSizeX) {
        next = this->initialize(imageSizeX, imageSizeY, firstX, firstY);
      } else {
        clear();
      }
    }
    void clear() {
      this->end = 0;
      this->strideHighToLow = 0;
      this->strideLowToHigh = 0;
      this->next = 0;
    }
    int writeLowInto(T * const output, const T & primary) {
      return saveAndUpdate(output, primary, this->strideLowToHigh);
    }
    int writeHighInto(T * const output, const T & other) {
      return saveAndUpdate(output, other, this->strideHighToLow);
    }
};

template <int WIN_SIZE_X, int WIN_SIZE_Y>
class FDWT53 {
  private:
    template <bool CHECKED_LOADER>
    struct FDWT53Column {
      VerticalDWTPixelLoader<int, CHECKED_LOADER> loader;
      int offset;
      int pixel0, pixel1, pixel2;
      void clear() {
        offset = pixel0 = pixel1 = pixel2 = 0;
        loader.clear();
      }
    };

    typedef TransformBuffer<int, WIN_SIZE_X, WIN_SIZE_Y + 3, 2> FDWT53Buffer;
    FDWT53Buffer buffer;
    enum { STRIDE = FDWT53Buffer::VERTICAL_STRIDE };

    struct Forward53Predict {
      void operator() (const int p, int & c, const int n) const {
        c -= (p + n) / 2;      
      }
    };

    struct Forward53Update {
      void operator() (const int p, int & c, const int n) const {
        c += (p + n + 2) / 4;  
      }
    };

    template <bool CHECKED>
    void initColumn(FDWT53Column<CHECKED> & column,
                               const int * const input,
                               const int sizeX, const int sizeY,
                               const int colIndex, const int firstY, int blockIdx_x, int blockIdx_y) {
      column.offset = buffer.getColumnOffset(colIndex);
      const int firstX = blockIdx_x * WIN_SIZE_X + colIndex;

      if(blockIdx_y == 0) {
        column.loader.init(sizeX, sizeY, firstX, firstY);
        column.pixel2 = column.loader.loadFrom(input);  
        column.pixel1 = column.loader.loadFrom(input);  
        column.pixel0 = column.loader.loadFrom(input);  
        column.loader.init(sizeX, sizeY, firstX, firstY + 1);
      } else {
        column.loader.init(sizeX, sizeY, firstX, firstY - 2);
        column.pixel0 = column.loader.loadFrom(input);
        column.pixel1 = column.loader.loadFrom(input);
        column.pixel2 = column.loader.loadFrom(input);
      }
    }

    template <bool CHECKED>
    void loadAndVerticallyTransform(FDWT53Column<CHECKED> & column,
                                               const int * const input) {
      buffer[column.offset + 0 * STRIDE] = column.pixel0;
      buffer[column.offset + 1 * STRIDE] = column.pixel1;
      buffer[column.offset + 2 * STRIDE] = column.pixel2;
      for(int i = 3; i < (3 + WIN_SIZE_Y); i++) 
      {
        buffer[column.offset + i * STRIDE] = column.loader.loadFrom(input);
      }
      column.pixel0 = buffer[column.offset + (WIN_SIZE_Y + 0) * STRIDE];
      column.pixel1 = buffer[column.offset + (WIN_SIZE_Y + 1) * STRIDE];
      column.pixel2 = buffer[column.offset + (WIN_SIZE_Y + 2) * STRIDE];
      buffer.forEachVerticalOdd(column.offset, Forward53Predict(), 0);
      buffer.forEachVerticalEven(column.offset, Forward53Update(), 0);
    }

    template <bool CHECK_LOADS, bool CHECK_WRITES>
    void transform(const int * const in, int * const out,
                              const int sizeX, const int sizeY,
                              const int winSteps, int blockIdx_x, int blockIdx_y, int threadIdx_x) {
      FDWT53Column<CHECK_LOADS> column;    
      FDWT53Column<CHECK_LOADS> boundaryColumn;  
      const int firstY = blockIdx_y * WIN_SIZE_Y * winSteps;
      initColumn(column, in, sizeX, sizeY, threadIdx_x, firstY, blockIdx_x, blockIdx_y); 
      boundaryColumn.clear();
      if(threadIdx_x < 3) {
        const int colId = threadIdx_x + ((threadIdx_x == 0) ? WIN_SIZE_X : -3);
        initColumn(boundaryColumn, in, sizeX, sizeY, colId, firstY, blockIdx_x, blockIdx_y);
      }
      const int outColumnIndex = parityIdx<WIN_SIZE_X>(threadIdx_x);
      const int outColumnOffset = buffer.getColumnOffset(outColumnIndex);
      const int outputFirstX = blockIdx_x * WIN_SIZE_X + outColumnIndex;
      VerticalDWTBandWriter<int, CHECK_WRITES> writer;
      writer.init(sizeX, sizeY, outputFirstX, firstY);
      for(int w = 0; w < winSteps; w++) {
        loadAndVerticallyTransform(column, in);
        if(threadIdx_x < 3) { 
          loadAndVerticallyTransform(boundaryColumn, in); 
        }
        buffer.forEachHorizontalOdd(2, WIN_SIZE_Y, Forward53Predict(), threadIdx_x);
        buffer.forEachHorizontalEven(2, WIN_SIZE_Y, Forward53Update(), threadIdx_x);
        for(int r = 2; r < (2 + WIN_SIZE_Y); r += 2) {
          writer.writeLowInto(out, buffer[outColumnOffset + r * STRIDE]);
          writer.writeHighInto(out, buffer[outColumnOffset + (r+1) * STRIDE]);
        }
      }
    }

  public:
    static void run(const int * const in, int * const out,
                               const int sx, const int sy, const int steps, int blockIdx_x, int blockIdx_y, int threadIdx_x) {
      FDWT53<WIN_SIZE_X, WIN_SIZE_Y> fdwt53;
      const int maxX = (blockIdx_x + 1) * WIN_SIZE_X + 1;
      const int maxY = (blockIdx_y + 1) * WIN_SIZE_Y * steps + 1;
      const bool atRightBoudary = maxX >= sx;
      const bool atBottomBoudary = maxY >= sy;
      if(atBottomBoudary) 
      {
        fdwt53.transform<true, true>(in, out, sx, sy, steps, blockIdx_x, blockIdx_y, threadIdx_x);
      } else if(atRightBoudary) 
      {
        fdwt53.transform<false, true>(in, out, sx, sy, steps, blockIdx_x, blockIdx_y, threadIdx_x);
      } else 
      {
        fdwt53.transform<false, false>(in, out, sx, sy, steps, blockIdx_x, blockIdx_y, threadIdx_x);
      }
    }
}; 

__kernel void cl_fdwt53Kernel(const int * const input, int * const output,
                               const int sizeX, const int sizeY,
                               const int winSteps, const int WIN_SX, const int WIN_SY) {
    FDWT53<WIN_SX, WIN_SY>::run(input, output, sizeX, sizeY, winSteps, get_group_id(0), get_group_id(1), get_local_id(0));
}

template <int WIN_SIZE_X, int WIN_SIZE_Y>
class FDWT97 {
  private:
    typedef TransformBuffer<float, WIN_SIZE_X, WIN_SIZE_Y + 7, 4> FDWT97Buffer;
    FDWT97Buffer buffer;
    enum { STRIDE = FDWT97Buffer::VERTICAL_STRIDE };

    template <bool CHECKED>
    struct FDWT97ColumnLoadingInfo {
      VerticalDWTPixelLoader<float, CHECKED> loader;  
      int offset;
    };

    void horizontalFDWT97(const int lines, const int firstLine, int threadIdx_x) {
      buffer.forEachHorizontalOdd(firstLine, lines, AddScaledSum(f97Predict1), threadIdx_x);
      buffer.forEachHorizontalEven(firstLine, lines, AddScaledSum(f97Update1), threadIdx_x);
      buffer.forEachHorizontalOdd(firstLine, lines, AddScaledSum(f97Predict2), threadIdx_x);
      buffer.forEachHorizontalEven(firstLine, lines, AddScaledSum(f97Update2), threadIdx_x);
      buffer.scaleHorizontal(scale97Div, scale97Mul, firstLine, lines, threadIdx_x);
    }

    template <bool CHECKED>
    void initColumn(FDWT97ColumnLoadingInfo<CHECKED> & column,
                              const int columnIndex, const float * const input, 
                              const int sizeX, const int sizeY,
                              const int firstY, int blockIdx_x, int blockIdx_y) {
      column.offset = buffer.getColumnOffset(columnIndex);
      const int firstX = blockIdx_x * WIN_SIZE_X + columnIndex;
      if(blockIdx_y == 0) {
        column.loader.init(sizeX, sizeY, firstX, firstY);
        buffer[column.offset + 4 * STRIDE] = column.loader.loadFrom(input);
        buffer[column.offset + 3 * STRIDE] = column.loader.loadFrom(input);
        buffer[column.offset + 5 * STRIDE] = column.loader.loadFrom(input);
        buffer[column.offset + 2 * STRIDE] = column.loader.loadFrom(input);
        buffer[column.offset + 6 * STRIDE] = column.loader.loadFrom(input);
        buffer[column.offset + 1 * STRIDE] = column.loader.loadFrom(input);
        buffer[column.offset + 0 * STRIDE] = column.loader.loadFrom(input);
        column.loader.init(sizeX, sizeY, firstX, firstY + 3);
      } else {
        column.loader.init(sizeX, sizeY, firstX, firstY - 4);
        for(int i = 0; i < 7; i++) {
          buffer[column.offset + i * STRIDE] = column.loader.loadFrom(input);
        }
      }
    }

    template <bool CHECKED>
    void loadWindowIntoColumn(const float * const input,
                                  FDWT97ColumnLoadingInfo<CHECKED> & column) {
      for(int i = 7; i < (7 + WIN_SIZE_Y); i++) {
        buffer[column.offset + i * STRIDE] = column.loader.loadFrom(input);
      }
    }

    template <bool CHECK_LOADS, bool CHECK_WRITES>
    void transform(const float * const in, float * const out,
                              const int sizeX, const int sizeY,
                              const int winSteps, int blockIdx_x, int blockIdx_y, int threadIdx_x) {
      FDWT97ColumnLoadingInfo<CHECK_LOADS> loadedColumn;
      FDWT97ColumnLoadingInfo<CHECK_LOADS> boundaryColumn;
      const int firstY = blockIdx_y * WIN_SIZE_Y * winSteps;
      initColumn(loadedColumn, threadIdx_x, in, sizeX, sizeY, firstY, blockIdx_x, blockIdx_y);
      boundaryColumn.offset = 0;
      boundaryColumn.loader.clear();
      if(threadIdx_x < 7) {
        const int colId = threadIdx_x + ((threadIdx_x < 3) ? WIN_SIZE_X : -7);
        initColumn(boundaryColumn, colId, in, sizeX, sizeY, firstY, blockIdx_x, blockIdx_y);
      }
      horizontalFDWT97(7, 0, threadIdx_x);
      const int outColumnIndex = parityIdx<WIN_SIZE_X>(threadIdx_x);
      const int firstX = blockIdx_x * WIN_SIZE_X + outColumnIndex;
      VerticalDWTBandWriter<float, CHECK_WRITES> writer;
      writer.init(sizeX, sizeY, firstX, firstY);
      const int outColumnOffset = buffer.getColumnOffset(outColumnIndex);
      for(int w = 0; w < winSteps; w++) {
        loadWindowIntoColumn(in, loadedColumn);
        if(threadIdx_x < 7) {
          loadWindowIntoColumn(in, boundaryColumn);
        }
        horizontalFDWT97(WIN_SIZE_Y, 7, threadIdx_x);
        float last7Lines[7];
        for(int i = 0; i < 7; i++) {
          last7Lines[i] = buffer[outColumnOffset + (WIN_SIZE_Y + i) * STRIDE];
        }
        buffer.forEachVerticalOdd(outColumnOffset, AddScaledSum(f97Predict1), threadIdx_x);
        buffer.forEachVerticalEven(outColumnOffset, AddScaledSum(f97Update1), threadIdx_x);
        buffer.forEachVerticalOdd(outColumnOffset, AddScaledSum(f97Predict2), threadIdx_x);
        buffer.forEachVerticalEven(outColumnOffset, AddScaledSum(f97Update2), threadIdx_x);
        for(int i = 4; i < (4 + WIN_SIZE_Y); i += 2) {
          const int index = outColumnOffset + i * STRIDE;
          writer.writeLowInto(out, buffer[index] * scale97Div);
          writer.writeHighInto(out, buffer[index + STRIDE] * scale97Mul);
        }
        for(int i = 0; i < 7; i++) {
          buffer[outColumnOffset + i * STRIDE] = last7Lines[i];
        }
      }
    }

  public:
    static void run(const float * const input, float * const output,
                               const int sx, const int sy, const int steps, int blockIdx_x, int blockIdx_y, int threadIdx_x) {
      FDWT97<WIN_SIZE_X, WIN_SIZE_Y> fdwt97;
      const int maxX = (blockIdx_x + 1) * WIN_SIZE_X + 3;
      const int maxY = (blockIdx_y + 1) * WIN_SIZE_Y * steps + 3;
      const bool atRightBoudary = maxX >= sx;
      const bool atBottomBoudary = maxY >= sy;
      if(atBottomBoudary) {
        fdwt97.transform<true, true>(input, output, sx, sy, steps, blockIdx_x, blockIdx_y, threadIdx_x);
      } else if(atRightBoudary) {
        fdwt97.transform<false, true>(input, output, sx, sy, steps, blockIdx_x, blockIdx_y, threadIdx_x);
      } else {
        fdwt97.transform<false, false>(input, output, sx, sy, steps, blockIdx_x, blockIdx_y, threadIdx_x);
      }
    }
}; 

__kernel void cl_fdwt97Kernel(const float * const input, float * const output,
                               const int sx, const int sy, const int steps, const int WIN_SX, const int WIN_SY) {
    FDWT97<WIN_SX, WIN_SY>::run(input, output, sx, sy, steps, get_group_id(0), get_group_id(1), get_local_id(0));
}

template <int WIN_SIZE_X, int WIN_SIZE_Y>
class RDWT53 {
  private: 
    typedef TransformBuffer<int, WIN_SIZE_X, WIN_SIZE_Y + 3, 2> RDWT53Buffer;
    RDWT53Buffer buffer;
    enum { STRIDE = RDWT53Buffer::VERTICAL_STRIDE };

    template <bool CHECKED>
    struct RDWT53Column {
      VerticalDWTBandLoader<int, CHECKED> loader;
      int offset;
      void clear() {
        offset = 0;
        loader.clear();
      }
    };

    struct Reverse53Update {
      void operator() (const int p, int & c, const int n) const {
        c -= (p + n + 2) / 4;  
      }
    };

    struct Reverse53Predict {
      void operator() (const int p, int & c, const int n) const {
        c += (p + n) / 2;      
      }
    };

    void horizontalTransform(const int lines, const int firstLine, int threadIdx_x) {
      buffer.forEachHorizontalEven(firstLine, lines, Reverse53Update(), threadIdx_x);
      buffer.forEachHorizontalOdd(firstLine, lines, Reverse53Predict(), threadIdx_x);
    }

    template <bool CHECKED>
    void loadWindowIntoColumn(const int * const input,
                                                RDWT53Column<CHECKED> & col) {
      for(int i = 3; i < (3 + WIN_SIZE_Y); i += 2) {
        buffer[col.offset + i * STRIDE] = col.loader.loadLowFrom(input);
        buffer[col.offset + (i + 1) * STRIDE] = col.loader.loadHighFrom(input);
      }
    }

    template <bool CHECKED>
    void initColumn(const int columnX, const int * const input, 
                               const int sizeX, const int sizeY,
                               RDWT53Column<CHECKED> & column,
                               const int firstY, int blockIdx_x, int blockIdx_y) {
      const int firstX = blockIdx_x * WIN_SIZE_X + columnX;
      column.offset = buffer.getColumnOffset(columnX);
      if(blockIdx_y == 0) {
        column.loader.init(sizeX, sizeY, firstX, firstY);
        buffer[column.offset + 1 * STRIDE] = column.loader.loadLowFrom(input);
        buffer[column.offset + 0 * STRIDE] = column.loader.loadHighFrom(input);
        buffer[column.offset + 2 * STRIDE] = column.loader.loadHighFrom(input);
      } else {
        column.loader.init(sizeX, sizeY, firstX, firstY - 1);
        buffer[column.offset + 0 * STRIDE] = column.loader.loadHighFrom(input);
        buffer[column.offset + 1 * STRIDE] = column.loader.loadLowFrom(input);
        buffer[column.offset + 2 * STRIDE] = column.loader.loadHighFrom(input);
      }
    }

    template<bool CHECKED_LOADS, bool CHECKED_WRITES>
    void transform(const int * const in, int * const out,
                              const int sizeX, const int sizeY,
                              const int winSteps, int blockIdx_x, int blockIdx_y, int threadIdx_x) {
      RDWT53Column<CHECKED_LOADS> column, boundaryColumn;
      const int firstY = blockIdx_y * WIN_SIZE_Y * winSteps;
      boundaryColumn.clear();
      if(threadIdx_x < 3) {
        const int colId = threadIdx_x + ((threadIdx_x != 2) ? WIN_SIZE_X : -3);
        initColumn(colId, in, sizeX, sizeY, boundaryColumn, firstY, blockIdx_x, blockIdx_y);
      }
      initColumn(parityIdx<WIN_SIZE_X>(threadIdx_x), in, sizeX, sizeY, column, firstY, blockIdx_x, blockIdx_y);
      horizontalTransform(3, 0, threadIdx_x);
      const int outX = blockIdx_x * WIN_SIZE_X + threadIdx_x;
      VerticalDWTPixelWriter<int, CHECKED_WRITES> writer;
      writer.init(sizeX, sizeY, outX, firstY);
      const int outputColumnOffset = buffer.getColumnOffset(threadIdx_x);
      for(int w = 0; w < winSteps; w++) {
        loadWindowIntoColumn(in, column);
        if(threadIdx_x < 3) {
          loadWindowIntoColumn(in, boundaryColumn);
        }
        horizontalTransform(WIN_SIZE_Y, 3, threadIdx_x);
        int last3Lines[3];
        last3Lines[0] = buffer[outputColumnOffset + (WIN_SIZE_Y + 0) * STRIDE];
        last3Lines[1] = buffer[outputColumnOffset + (WIN_SIZE_Y + 1) * STRIDE];
        last3Lines[2] = buffer[outputColumnOffset + (WIN_SIZE_Y + 2) * STRIDE];
        buffer.forEachVerticalOdd(outputColumnOffset, Reverse53Update(), threadIdx_x);
        buffer.forEachVerticalEven(outputColumnOffset, Reverse53Predict(), threadIdx_x);
        for(int i = 1; i < (1 + WIN_SIZE_Y); i++) {
          writer.writeInto(out, buffer[outputColumnOffset + i * STRIDE]);
        }
        buffer[outputColumnOffset + 0 * STRIDE] = last3Lines[0];
        buffer[outputColumnOffset + 1 * STRIDE] = last3Lines[1];
        buffer[outputColumnOffset + 2 * STRIDE] = last3Lines[2];
      }
    }

  public:
    static void run(const int * const input, int * const output,
                               const int sx, const int sy, const int steps, int blockIdx_x, int blockIdx_y, int threadIdx_x) {
      RDWT53<WIN_SIZE_X, WIN_SIZE_Y> rdwt53;
