template <int WIN_SIZE_X, int WIN_SIZE_Y>
class RDWT97 {
  private:
    template <bool CHECKED>
    struct RDWT97Column  {
      VerticalDWTBandLoader<float, CHECKED> loader;
      int offset;
      void clear() {
        loader.clear();
        offset = 0;
      }
    };
    typedef TransformBuffer<float, WIN_SIZE_X, WIN_SIZE_Y + 7, 4> RDWT97Buffer;
    RDWT97Buffer buffer;
    enum { STRIDE = RDWT97Buffer::VERTICAL_STRIDE };

    void horizontalRDWT97(int lines, int firstLine, int threadIdx_x) {
      buffer.scaleHorizontal(scale97Mul, scale97Div, firstLine, lines, threadIdx_x);
      buffer.forEachHorizontalEven(firstLine, lines, AddScaledSum(r97update2), threadIdx_x);
      buffer.forEachHorizontalOdd(firstLine, lines, AddScaledSum(r97predict2), threadIdx_x);
      buffer.forEachHorizontalEven(firstLine, lines, AddScaledSum(r97update1), threadIdx_x);
      buffer.forEachHorizontalOdd(firstLine, lines, AddScaledSum(r97Predict1), threadIdx_x);
    }

    template <bool CHECKED>
    void initColumn(const int colIndex, const float * const input, 
                               const int sizeX, const int sizeY,
                               RDWT97Column<CHECKED> & column,
                               const int firstY, int blockIdx_x, int blockIdx_y) {
      const int firstX = blockIdx_x * WIN_SIZE_X + colIndex;
      column.offset = buffer.getColumnOffset(colIndex);
      if(blockIdx_y == 0) {
        column.loader.init(sizeX, sizeY, firstX, firstY);
        buffer[column.offset + 3 * STRIDE] = column.loader.loadLowFrom(input);
        buffer[column.offset + 4 * STRIDE] = column.loader.loadHighFrom(input);
        buffer[column.offset + 2 * STRIDE] = column.loader.loadHighFrom(input);
        buffer[column.offset + 5 * STRIDE] = column.loader.loadLowFrom(input);
        buffer[column.offset + 1 * STRIDE] = column.loader.loadLowFrom(input);
        buffer[column.offset + 6 * STRIDE] = column.loader.loadHighFrom(input);
        buffer[column.offset + 0 * STRIDE] = column.loader.loadHighFrom(input);
      } else {
        column.loader.init(sizeX, sizeY, firstX, firstY - 3);
        buffer[column.offset + 0 * STRIDE] = column.loader.loadHighFrom(input);
        buffer[column.offset + 1 * STRIDE] = column.loader.loadLowFrom(input);
        buffer[column.offset + 2 * STRIDE] = column.loader.loadHighFrom(input);
        buffer[column.offset + 3 * STRIDE] = column.loader.loadLowFrom(input);
        buffer[column.offset + 4 * STRIDE] = column.loader.loadHighFrom(input);
        buffer[column.offset + 5 * STRIDE] = column.loader.loadLowFrom(input);
        buffer[column.offset + 6 * STRIDE] = column.loader.loadHighFrom(input);
      }
    }

    template <bool CHECKED>
    void loadWindowIntoColumn(RDWT97Column<CHECKED> & col,
                                                const float * const input) {
      for(int i = 7; i < (7 + WIN_SIZE_Y); i += 2) {
        buffer[col.offset + i * STRIDE] = col.loader.loadLowFrom(input);
        buffer[col.offset + (i + 1) * STRIDE] = col.loader.loadHighFrom(input);
      }
    }

    template <bool CHECKED_LOADS, bool CHECKED_WRITES>
    void transform(const float * const in, float * const out,
                              const int sizeX, const int sizeY,
                              const int winSteps, int blockIdx_x, int blockIdx_y, int threadIdx_x) {
      RDWT97Column<CHECKED_LOADS> column;
      RDWT97Column<CHECKED_LOADS> boundaryColumn;
      const int firstY = blockIdx_y * WIN_SIZE_Y * winSteps;
      boundaryColumn.clear();
      if(threadIdx_x < 7) {
        const int colId = threadIdx_x + ((threadIdx_x < 4) ? WIN_SIZE_X : -7);
        initColumn(colId, in, sizeX, sizeY, boundaryColumn, firstY, blockIdx_x, blockIdx_y);
      }
      initColumn(parityIdx<WIN_SIZE_X>(threadIdx_x), in, sizeX, sizeY, column, firstY, blockIdx_x, blockIdx_y);
      horizontalRDWT97(7, 0, threadIdx_x);
      const int outputX = blockIdx_x * WIN_SIZE_X + threadIdx_x;
      VerticalDWTPixelWriter<float, CHECKED_WRITES> writer;
      writer.init(sizeX, sizeY, outputX, firstY);
      const int outColumnOffset = buffer.getColumnOffset(threadIdx_x);
      for(int w = 0; w < winSteps; w++) {
        loadWindowIntoColumn(column, in);
        if(threadIdx_x < 7) {
          loadWindowIntoColumn(boundaryColumn, in);
        }
        horizontalRDWT97(WIN_SIZE_Y, 7, threadIdx_x);
        float last7Lines[7];
        for(int i = 0; i < 7; i++) {
          last7Lines[i] = buffer[outColumnOffset + (WIN_SIZE_Y + i) * STRIDE];
        }
        buffer.scaleVertical(scale97Div, scale97Mul, outColumnOffset, WIN_SIZE_Y + 7, 0);
        buffer.forEachVerticalOdd(outColumnOffset, AddScaledSum(r97update2), threadIdx_x);
        buffer.forEachVerticalEven(outColumnOffset, AddScaledSum(r97predict2), threadIdx_x);
        buffer.forEachVerticalOdd(outColumnOffset, AddScaledSum(r97update1), threadIdx_x);
        buffer.forEachVerticalEven(outColumnOffset, AddScaledSum(r97Predict1), threadIdx_x);
        for(int i = 3; i < (3 + WIN_SIZE_Y); i++) {
          writer.writeInto(out, buffer[outColumnOffset + i * STRIDE]);
        }
        for(int i = 0; i < 7; i++) {
          buffer[outColumnOffset + i * STRIDE] = last7Lines[i];
        }
      }
    }

  public:
    static void run(const float * const input, float * const output,
                               const int sx, const int sy, const int steps, int blockIdx_x, int blockIdx_y, int threadIdx_x) {
      RDWT97<WIN_SIZE_X, WIN_SIZE_Y> rdwt97;
      const int maxX = (blockIdx_x + 1) * WIN_SIZE_X + 3;
      const int maxY = (blockIdx_y + 1) * WIN_SIZE_Y * steps + 3;
      const bool atRightBoudary = maxX >= sx;
      const bool atBottomBoudary = maxY >= sy;
      if(atBottomBoudary) {
        rdwt97.transform<true, true>(input, output, sx, sy, steps, blockIdx_x, blockIdx_y, threadIdx_x);
      } else if(atRightBoudary) {
        rdwt97.transform<false, true>(input, output, sx, sy, steps, blockIdx_x, blockIdx_y, threadIdx_x);
      } else {
        rdwt97.transform<false, false>(input, output, sx, sy, steps, blockIdx_x, blockIdx_y, threadIdx_x);
      }
    }
}; 

