kernel void cl_fdwt53Kernel(const int *input, int *output,
                            int sizeX, int sizeY,
                            int winSteps,
                            int WIN_SX, int WIN_SY) {
    int WIN_SIZE_X = WIN_SX;
    int WIN_SIZE_Y = WIN_SY;

    const int VERTICAL_STRIDE = 2 + (WIN_SIZE_X / 2);
    const int BUFFER_SIZE = VERTICAL_STRIDE * (WIN_SIZE_Y + 3);
    const int SHM_BANKS = 32;
    const int PADDING = SHM_BANKS - ((BUFFER_SIZE + SHM_BANKS / 2) % SHM_BANKS);
    const int ODD_OFFSET = BUFFER_SIZE + PADDING;

    int data[2 * BUFFER_SIZE + PADDING];

    int threadIdx_x = get_local_id(0);
    int blockIdx_x = get_group_id(0);
    int blockIdx_y = get_group_id(1);

    int firstY = blockIdx_y * WIN_SIZE_Y * winSteps;
    int firstX_base = blockIdx_x * WIN_SIZE_X;

    int offset = (threadIdx_x + 2) / 2 + ((threadIdx_x + 2) & 1) * ODD_OFFSET;
    int boundary_offset = 0;

    int pixel0, pixel1, pixel2;
    int b_pixel0, b_pixel1, b_pixel2;

    int loader_x = firstX_base + threadIdx_x;
    int loader_y = (blockIdx_y == 0) ? firstY : firstY - 2;
    int b_loader_x = firstX_base + threadIdx_x + ((threadIdx_x == 0) ? WIN_SIZE_X : -3);
    int b_loader_y = (blockIdx_y == 0) ? firstY : firstY - 2;

    mirror(&loader_x, sizeX);
    mirror(&b_loader_x, sizeX);

    int idx0 = loader_x + loader_y * sizeX;
    int idx1 = loader_x + (loader_y + 1) * sizeX;
    int idx2 = loader_x + (loader_y + 2) * sizeX;

    if (loader_y < 0) idx0 = loader_x + (-loader_y) * sizeX;
    if (loader_y + 1 >= sizeY) idx1 = loader_x + (2 * sizeY - 2 - (loader_y + 1)) * sizeX;
    if (loader_y + 2 >= sizeY) idx2 = loader_x + (2 * sizeY - 2 - (loader_y + 2)) * sizeX;

    pixel2 = (loader_y + 2 < sizeY && loader_y + 2 >= 0) ? input[idx2] : ((loader_y + 2 >= sizeY) ? input[loader_x + (2 * sizeY - 2 - (loader_y + 2)) * sizeX] : input[loader_x + (-loader_y - 2) * sizeX]);
    pixel1 = (loader_y + 1 < sizeY && loader_y + 1 >= 0) ? input[idx1] : ((loader_y + 1 >= sizeY) ? input[loader_x + (2 * sizeY - 2 - (loader_y + 1)) * sizeX] : input[loader_x + (-loader_y - 1) * sizeX]);
    pixel0 = (loader_y >= 0 && loader_y < sizeY) ? input[idx0] : ((loader_y >= sizeY) ? input[loader_x + (2 * sizeY - 2 - loader_y) * sizeX] : input[loader_x + (-loader_y) * sizeX]);

    if (threadIdx_x < 3) {
        int b_idx0 = b_loader_x + b_loader_y * sizeX;
        int b_idx1 = b_loader_x + (b_loader_y + 1) * sizeX;
        int b_idx2 = b_loader_x + (b_loader_y + 2) * sizeX;
        if (b_loader_y < 0) b_idx0 = b_loader_x + (-b_loader_y) * sizeX;
        if (b_loader_y + 1 >= sizeY) b_idx1 = b_loader_x + (2 * sizeY - 2 - (b_loader_y + 1)) * sizeX;
        if (b_loader_y + 2 >= sizeY) b_idx2 = b_loader_x + (2 * sizeY - 2 - (b_loader_y + 2)) * sizeX;

        b_pixel2 = (b_loader_y + 2 < sizeY && b_loader_y + 2 >= 0) ? input[b_idx2] : ((b_loader_y + 2 >= sizeY) ? input[b_loader_x + (2 * sizeY - 2 - (b_loader_y + 2)) * sizeX] : input[b_loader_x + (-b_loader_y - 2) * sizeX]);
        b_pixel1 = (b_loader_y + 1 < sizeY && b_loader_y + 1 >= 0) ? input[b_idx1] : ((b_loader_y + 1 >= sizeY) ? input[b_loader_x + (2 * sizeY - 2 - (b_loader_y + 1)) * sizeX] : input[b_loader_x + (-b_loader_y - 1) * sizeX]);
        b_pixel0 = (b_loader_y >= 0 && b_loader_y < sizeY) ? input[b_idx0] : ((b_loader_y >= sizeY) ? input[b_loader_x + (2 * sizeY - 2 - b_loader_y) * sizeX] : input[b_loader_x + (-b_loader_y) * sizeX];
    }

    for (int w = 0; w < winSteps; w++) {
        data[offset + 0 * VERTICAL_STRIDE] = pixel0;
        data[offset + 1 * VERTICAL_STRIDE] = pixel1;
        data[offset + 2 * VERTICAL_STRIDE] = pixel2;

        for (int i = 3; i < (3 + WIN_SIZE_Y); i++) {
            int y = loader_y + i;
            int x = loader_x;
            if (y >= sizeY) y = 2 * sizeY - 2 - y;
            if (y < 0) y = -y;
            if (x >= sizeX) x = 2 * sizeX - 2 - x;
            if (x < 0) x = -x;
            data[offset + i * VERTICAL_STRIDE] = input[x + y * sizeX];
        }

        if (threadIdx_x < 3) {
            int b_off = boundary_offset;
            data[b_off + 0 * VERTICAL_STRIDE] = b_pixel0;
            data[b_off + 1 * VERTICAL_STRIDE] = b_pixel1;
            data[b_off + 2 * VERTICAL_STRIDE] = b_pixel2;
            for (int i = 3; i < (3 + WIN_SIZE_Y); i++) {
                int y = b_loader_y + i;
                int x = b_loader_x;
                if (y >= sizeY) y = 2 * sizeY - 2 - y;
                if (y < 0) y = -y;
                if (x >= sizeX) x = 2 * sizeX - 2 - x;
                if (x < 0) x = -x;
                data[b_off + i * VERTICAL_STRIDE] = input[x + y * sizeX];
            }
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        for (int r = 1; r < WIN_SIZE_Y + 3 - 1; r += 2) {
            int prev = data[offset + (r - 1) * VERTICAL_STRIDE];
            int next = data[offset + (r + 1) * VERTICAL_STRIDE];
            int &center = data[offset + r * VERTICAL_STRIDE];
            center -= (prev + next) / 2;
        }
        for (int r = 2; r < WIN_SIZE_Y + 3 - 2; r += 2) {
            int prev = data[offset + (r - 1) * VERTICAL_STRIDE];
            int next = data[offset + (r + 1) * VERTICAL_STRIDE];
            int &center = data[offset + r * VERTICAL_STRIDE];
            center += (prev + next + 2) / 4;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        int outColumnIndex = parityIdx(threadIdx_x, WIN_SIZE_X);
        int outOffset = (outColumnIndex + 2) / 2 + ((outColumnIndex + 2) & 1) * ODD_OFFSET;
        int outputFirstX = firstX_base + outColumnIndex;

        for (int r = 2; r < (2 + WIN_SIZE_Y); r += 2) {
            int y_low = firstY + w * WIN_SIZE_Y * winSteps / winSteps + r;
            int y_high = y_low + 1;
            if (y_low < sizeY && outputFirstX < sizeX) {
                output[outputFirstX + y_low * sizeX] = data[outOffset + r * VERTICAL_STRIDE];
            }
            if (y_high < sizeY && outputFirstX < sizeX) {
                output[outputFirstX + y_high * sizeX] = data[outOffset + (r + 1) * VERTICAL_STRIDE];
            }
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        loader_y += WIN_SIZE_Y;
        b_loader_y += WIN_SIZE_Y;

        int new_idx0 = loader_x + loader_y * sizeX;
        int new_idx1 = loader_x + (loader_y + 1) * sizeX;
        int new_idx2 = loader_x + (loader_y + 2) * sizeX;
        if (loader_y >= sizeY) {
            new_idx0 = loader_x + (2 * sizeY - 2 - loader_y) * sizeX;
            new_idx1 = loader_x + (2 * sizeY - 2 - (loader_y + 1)) * sizeX;
            new_idx2 = loader_x + (2 * sizeY - 2 - (loader_y + 2)) * sizeX;
        }
        pixel0 = input[new_idx0];
        pixel1 = input[new_idx1];
        pixel2 = input[new_idx2];

        if (threadIdx_x < 3) {
            int b_new_idx0 = b_loader_x + b_loader_y * sizeX;
            int b_new_idx1 = b_loader_x + (b_loader_y + 1) * sizeX;
            int b_new_idx2 = b_loader_x + (b_loader_y + 2) * sizeX;
            if (b_loader_y >= sizeY) {
                b_new_idx0 = b_loader_x + (2 * sizeY - 2 - b_loader_y) * sizeX;
                b_new_idx1 = b_loader_x + (2 * sizeY - 2 - (b_loader_y + 1)) * sizeX;
                b_new_idx2 = b_loader_x + (2 * sizeY - 2 - (b_loader_y + 2)) * sizeX;
            }
            b_pixel0 = input[b_new_idx0];
            b_pixel1 = input[b_new_idx1];
            b_pixel2 = input[b_new_idx2];
        }
    }
}

kernel void cl_fdwt97Kernel(const float *input, float *output,
