                            int WIN_SX, int WIN_SY) {
    int WIN_SIZE_X = WIN_SX;
    int WIN_SIZE_Y = WIN_SY;

    const int VERTICAL_STRIDE = 4 + (WIN_SIZE_X / 2);
    const int BUFFER_SIZE = VERTICAL_STRIDE * (WIN_SIZE_Y + 7);
    const int SHM_BANKS = 32;
    const int PADDING = SHM_BANKS - ((BUFFER_SIZE + SHM_BANKS / 2) % SHM_BANKS);
    const int ODD_OFFSET = BUFFER_SIZE + PADDING;

    float data[2 * BUFFER_SIZE + PADDING];

    int threadIdx_x = get_local_id(0);
    int blockIdx_x = get_group_id(0);
    int blockIdx_y = get_group_id(1);

    int firstY = blockIdx_y * WIN_SIZE_Y * steps;
    int firstX_base = blockIdx_x * WIN_SIZE_X;

    int offset = (threadIdx_x + 4) / 2 + ((threadIdx_x + 4) & 1) * ODD_OFFSET;

    int loader_x = firstX_base + threadIdx_x;
    int loader_y = (blockIdx_y == 0) ? firstY : firstY - 4;
    mirror(&loader_x, sx);

    for (int i = 0; i < 7; i++) {
        int y = loader_y + i;
        if (y >= sy) y = 2 * sy - 2 - y;
        if (y < 0) y = -y;
        data[offset + i * VERTICAL_STRIDE] = input[loader_x + y * sx];
    }

    for (int w = 0; w < steps; w++) {
        for (int i = 7; i < (7 + WIN_SIZE_Y); i++) {
            int y = loader_y + i;
            if (y >= sy) y = 2 * sy - 2 - y;
            if (y < 0) y = -y;
            data[offset + i * VERTICAL_STRIDE] = input[loader_x + y * sx];
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        for (int line = 7; line < 7 + WIN_SIZE_Y - 1; line += 2) {
            float p = data[offset + (line - 1) * VERTICAL_STRIDE];
            float n = data[offset + (line + 1) * VERTICAL_STRIDE];
            data[offset + line * VERTICAL_STRIDE] += f97Predict1 * (p + n);
        }
        for (int line = 8; line < 7 + WIN_SIZE_Y - 2; line += 2) {
            float p = data[offset + (line - 1) * VERTICAL_STRIDE];
            float n = data[offset + (line + 1) * VERTICAL_STRIDE];
            data[offset + line * VERTICAL_STRIDE] += f97Update1 * (p + n);
        }
        for (int line = 7; line < 7 + WIN_SIZE_Y - 1; line += 2) {
            float p = data[offset + (line - 1) * VERTICAL_STRIDE];
            float n = data[offset + (line + 1) * VERTICAL_STRIDE];
            data[offset + line * VERTICAL_STRIDE] += f97Predict2 * (p + n);
        }
        for (int line = 8; line < 7 + WIN_SIZE_Y - 2; line += 2) {
            float p = data[offset + (line - 1) * VERTICAL_STRIDE];
            float n = data[offset + (line + 1) * VERTICAL_STRIDE];
            data[offset + line * VERTICAL_STRIDE] += f97Update2 * (p + n);
        }

        for (int i = 4; i < (4 + WIN_SIZE_Y); i += 2) {
            int y_out = firstY + w * WIN_SIZE_Y * steps / steps + i;
            if (y_out < sy && loader_x < sx) {
                output[loader_x + y_out * sx] = data[offset + i * VERTICAL_STRIDE] * scale97Div;
                if (i + 1 < 7 + WIN_SIZE_Y && y_out + 1 < sy) {
                    output[loader_x + (y_out + 1) * sx] = data[offset + (i + 1) * VERTICAL_STRIDE] * scale97Mul;
                }
            }
        }

        barrier(CLK_LOCAL_MEM_FENCE);
        loader_y += WIN_SIZE_Y;
    }
}

kernel void cl_rdwt53Kernel(const int *in, int *out,
                            int sx, int sy, int steps,
                            int WIN_SX, int WIN_SY) {
    int WIN_SIZE_X = WIN_SX;
    int WIN_SIZE_Y = WIN_SY;

    const int VERTICAL_STRIDE = 2 + (WIN_SIZE_X / 2);
    const int BUFFER_SIZE = VERTICAL_STRIDE * (WIN_SIZE_Y + 3);
    const int SHM_BANKS = 32;
    const int PADDING = SHM_BANKS - ((BUFFER_SIZE + SHM_BANKS / 2) % SHM_BANKS);
    const int ODD_OFFSET = BUFFER_SIZE + PADDING;

    int data[2 * BUFFER_SIZE + PADDING];

    int threadIdx_x = get_local_id(0);
    int blockIdx_x = get_group_id(0);
    int blockIdx_y = get_group_id(1);

    int firstY = blockIdx_y * WIN_SIZE_Y * steps;
    int firstX_base = blockIdx_x * WIN_SIZE_X;

    int offset = (threadIdx_x) / 2 + ((threadIdx_x) & 1) * ODD_OFFSET;

    int loader_x = firstX_base + threadIdx_x;
    int loader_y = (blockIdx_y == 0) ? firstY : firstY - 1;
    mirror(&loader_x, sx);

    if (blockIdx_y == 0) {
        data[offset + 1 * VERTICAL_STRIDE] = in[loader_x + loader_y * sx];
        int y0 = loader_y; if (y0 >= sy) y0 = 2*sy-2-y0; if (y0 < 0) y0 = -y0;
        int y2 = loader_y + 2; if (y2 >= sy) y2 = 2*sy-2-y2; if (y2 < 0) y2 = -y2;
        data[offset + 0 * VERTICAL_STRIDE] = in[loader_x + y2 * sx];
        data[offset + 2 * VERTICAL_STRIDE] = in[loader_x + y2 * sx];
    } else {
        int y0 = loader_y; if (y0 >= sy) y0 = 2*sy-2-y0; if (y0 < 0) y0 = -y0;
        int y1 = loader_y + 1; if (y1 >= sy) y1 = 2*sy-2-y1; if (y1 < 0) y1 = -y1;
        int y2 = loader_y + 2; if (y2 >= sy) y2 = 2*sy-2-y2; if (y2 < 0) y2 = -y2;
        data[offset + 0 * VERTICAL_STRIDE] = in[loader_x + y2 * sx];
        data[offset + 1 * VERTICAL_STRIDE] = in[loader_x + y1 * sx];
        data[offset + 2 * VERTICAL_STRIDE] = in[loader_x + y2 * sx];
    }

    for (int w = 0; w < steps; w++) {
        for (int i = 3; i < (3 + WIN_SIZE_Y); i += 2) {
            int y = loader_y + i;
            if (y >= sy) y = 2 * sy - 2 - y;
            if (y < 0) y = -y;
            data[offset + i * VERTICAL_STRIDE] = in[loader_x + y * sx];
            int y_next = loader_y + i + 1;
            if (y_next >= sy) y_next = 2 * sy - 2 - y_next;
            if (y_next < 0) y_next = -y_next;
            data[offset + (i + 1) * VERTICAL_STRIDE] = in[loader_x + y_next * sx];
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        for (int r = 3 + WIN_SIZE_Y - 2; r >= 3; r -= 2) {
            int prev = data[offset + (r - 1) * VERTICAL_STRIDE];
            int next = data[offset + (r + 1) * VERTICAL_STRIDE];
            data[offset + r * VERTICAL_STRIDE] -= (prev + next + 2) / 4;
        }
        for (int r = 3 + WIN_SIZE_Y - 1; r >= 3; r -= 2) {
            int prev = data[offset + (r - 1) * VERTICAL_STRIDE];
            int next = data[offset + (r + 1) * VERTICAL_STRIDE];
            data[offset + r * VERTICAL_STRIDE] += (prev + next) / 2;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        int outX = firstX_base + threadIdx_x;
        int outY_base = firstY + w * WIN_SIZE_Y * steps / steps;

        for (int i = 1; i < (1 + WIN_SIZE_Y); i++) {
            int y_out = outY_base + i;
            if (y_out < sy && outX < sx) {
                out[outX + y_out * sx] = data[offset + i * VERTICAL_STRIDE];
            }
        }

        barrier(CLK_LOCAL_MEM_FENCE);
        loader_y += WIN_SIZE_Y;
    }
}

kernel void cl_rdwt97Kernel(const float *in, float *out,
                            int sx, int sy, int steps,
                            int WIN_SX, int WIN_SY) {
    int WIN_SIZE_X = WIN_SX;
    int WIN_SIZE_Y = WIN_SY;

    const int VERTICAL_STRIDE = 4 + (WIN_SIZE_X / 2);
    const int BUFFER_SIZE = VERTICAL_STRIDE * (WIN_SIZE_Y + 7);
    const int SHM_BANKS = 32;
    const int PADDING = SHM_BANKS - ((BUFFER_SIZE + SHM_BANKS / 2) % SHM_BANKS);
    const int ODD_OFFSET = BUFFER_SIZE + PADDING;

    float data[2 * BUFFER_SIZE + PADDING];

    int threadIdx_x = get_local_id(0);
    int blockIdx_x = get_group_id(0);
    int blockIdx_y = get_group_id(1);

    int firstY = blockIdx_y * WIN_SIZE_Y * steps;
    int firstX_base = blockIdx_x * WIN_SIZE_X;

    int offset = (threadIdx_x) / 2 + ((threadIdx_x) & 1) * ODD_OFFSET;

    int loader_x = firstX_base + threadIdx_x;
    int loader_y = (blockIdx_y == 0) ? firstY : firstY - 3;
    mirror(&loader_x, sx);

    if (blockIdx_y == 0) {
        int y3 = loader_y + 3; if (y3 >= sy) y3 = 2*sy-2-y3; if (y3 < 0) y3 = -y3;
        int y4 = loader_y + 4; if (y4 >= sy) y4 = 2*sy-2-y4; if (y4 < 0) y4 = -y4;
        int y2 = loader_y + 2; if (y2 >= sy) y2 = 2*sy-2-y2; if (y2 < 0) y2 = -y2;
        int y5 = loader_y + 5; if (y5 >= sy) y5 = 2*sy-2-y5; if (y5 < 0) y5 = -y5;
        int y1 = loader_y + 1; if (y1 >= sy) y1 = 2*sy-2-y1; if (y1 < 0) y1 = -y1;
        int y6 = loader_y + 6; if (y6 >= sy) y6 = 2*sy-2-y6; if (y6 < 0) y6 = -y6;
        int y0 = loader_y; if (y0 >= sy) y0 = 2*sy-2-y0; if (y0 < 0) y0 = -y0;

        data[offset + 3 * VERTICAL_STRIDE] = in[loader_x + y3 * sx];
        data[offset + 4 * VERTICAL_STRIDE] = in[loader_x + y4 * sx];
        data[offset + 2 * VERTICAL_STRIDE] = in[loader_x + y2 * sx];
        data[offset + 5 * VERTICAL_STRIDE] = in[loader_x + y5 * sx];
        data[offset + 1 * VERTICAL_STRIDE] = in[loader_x + y1 * sx];
        data[offset + 6 * VERTICAL_STRIDE] = in[loader_x + y6 * sx];
        data[offset + 0 * VERTICAL_STRIDE] = in[loader_x + y0 * sx];
    } else {
        for (int i = 0; i < 7; i++) {
            int y = loader_y + i;
            if (y >= sy) y = 2 * sy - 2 - y;
            if (y < 0) y = -y;
            data[offset + i * VERTICAL_STRIDE] = in[loader_x + y * sx];
        }
    }

    for (int w = 0; w < steps; w++) {
        for (int i = 7; i < (7 + WIN_SIZE_Y); i += 2) {
            int y = loader_y + i;
            if (y >= sy) y = 2 * sy - 2 - y;
            if (y < 0) y = -y;
            data[offset + i * VERTICAL_STRIDE] = in[loader_x + y * sx];
            int y_next = loader_y + i + 1;
            if (y_next >= sy) y_next = 2 * sy - 2 - y_next;
            if (y_next < 0) y_next = -y_next;
            data[offset + (i + 1) * VERTICAL_STRIDE] = in[loader_x + y_next * sx];
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        for (int line = 7 + WIN_SIZE_Y - 1; line >= 7; line -= 2) {
            float p = data[offset + (line - 1) * VERTICAL_STRIDE];
            float n = data[offset + (line + 1) * VERTICAL_STRIDE];
            data[offset + line * VERTICAL_STRIDE] += r97update2 * (p + n);
        }
        for (int line = 7 + WIN_SIZE_Y - 2; line >= 7; line -= 2) {
            float p = data[offset + (line - 1) * VERTICAL_STRIDE];
            float n = data[offset + (line + 1) * VERTICAL_STRIDE];
            data[offset + line * VERTICAL_STRIDE] += r97predict2 * (p + n);
        }
        for (int line = 7 + WIN_SIZE_Y - 1; line >= 7; line -= 2) {
            float p = data[offset + (line - 1) * VERTICAL_STRIDE];
            float n = data[offset + (line + 1) * VERTICAL_STRIDE];
            data[offset + line * VERTICAL_STRIDE] += r97update1 * (p + n);
        }
        for (int line = 7 + WIN_SIZE_Y - 2; line >= 7; line -= 2) {
            float p = data[offset + (line - 1) * VERTICAL_STRIDE];
            float n = data[offset + (line + 1) * VERTICAL_STRIDE];
            data[offset + line * VERTICAL_STRIDE] += r97Predict1 * (p + n);
        }

        int outX = firstX_base + threadIdx_x;
        int outY_base = firstY + w * WIN_SIZE_Y * steps / steps;

        for (int i = 3; i < (3 + WIN_SIZE_Y); i++) {
            int y_out = outY_base + i;
            if (y_out < sy && outX < sx) {
                out[outX + y_out * sx] = data[offset + i * VERTICAL_STRIDE];
            }
        }

        barrier(CLK_LOCAL_MEM_FENCE);
        loader_y += WIN_SIZE_Y;
    }
}

