}

kernel void c_CopySrcToComponents_float(cl_mem d_r, cl_mem d_g, cl_mem d_b,
                                  cl_mem d_src,
                                  int pixels)
{
    int x  = get_local_id(0);
    int gX = get_local_size(0) * get_group_id(0);

    unsigned char sData[THREADS*3];

    if ( (x*4) < THREADS*3 ) {
        float *s = (float *)d_src;
        float *d = (float *)sData;
        d[x] = s[((gX*3)>>2) + x];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    float r, g, b;

    int offset = x*3;
    r = (float)(sData[offset]);
    g = (float)(sData[offset+1]);
    b = (float)(sData[offset+2]);

    int globalOutputPosition = gX + x;
    if (globalOutputPosition < pixels) {
        storeComponents_float((float*)d_r, (float*)d_g, (float*)d_b, r, g, b, globalOutputPosition);
    }
}

