const char *kernel_source = 
"__kernel void Fan1(__global float *m_cuda, __global float *a_cuda, int Size, int t)\n"
"{   \n"
"    int idx = get_global_id(0);\n"
"    if(idx >= Size-1-t) return;\n"
"    m_cuda[Size*(idx+t+1)+t] = a_cuda[Size*(idx+t+1)+t] / a_cuda[Size*t+t];\n"
"}\n"
"\n"
"__kernel void Fan2(__global float *m_cuda, __global float *a_cuda, __global float *b_cuda, int Size, int j1, int t)\n"
"{\n"
"    int xidx = get_global_id(0);\n"
"    int yidx = get_global_id(1);\n"
"\n"
"    if(xidx >= Size-1-t) return;\n"
"    if(yidx >= Size-t) return;\n"
"\n"
"    a_cuda[Size*(xidx+1+t)+(yidx+t)] -= m_cuda[Size*(xidx+1+t)+t] * a_cuda[Size*t+(yidx+t)];\n"
"\n"
"    if(yidx == 0){\n"
"        b_cuda[xidx+1+t] -= m_cuda[Size*(xidx+1+t)+t] * b_cuda[t];\n"
"    }\n"
"}\n";

void ForwardSub()
{
	int t;
    cl_mem m_cuda, a_cuda, b_cuda;
    cl_int status;

    // Initialize OpenCL
    cl_platform_id platform;
    cl_device_id device;
    cl_context context;
    cl_command_queue commandQueue;
    cl_program program;
    cl_kernel kernelFan1, kernelFan2;

    cl_uint numPlatforms;
    status = clGetPlatformIDs(1, &platform, &numPlatforms);
    checkCLError(status, "Getting platform");

    status = clGetDeviceIDs(platform, CL_DEVICE_TYPE_ALL, 1, &device, NULL);
    checkCLError(status, "Getting device");

    context = clCreateContext(NULL, 1, &device, NULL, NULL, &status);
    checkCLError(status, "Creating context");

    commandQueue = clCreateCommandQueue(context, device, 0, &status);
    checkCLError(status, "Creating command queue");

    // Create buffers
    m_cuda = clCreateBuffer(context, CL_MEM_READ_WRITE, Size * Size * sizeof(float), NULL, &status);
    checkCLError(status, "Creating m buffer");

    a_cuda = clCreateBuffer(context, CL_MEM_READ_WRITE, Size * Size * sizeof(float), NULL, &status);
    checkCLError(status, "Creating a buffer");

    b_cuda = clCreateBuffer(context, CL_MEM_READ_WRITE, Size * sizeof(float), NULL, &status);
    checkCLError(status, "Creating b buffer");

    // Copy data to device
    status = clEnqueueWriteBuffer(commandQueue, m_cuda, CL_TRUE, 0, Size * Size * sizeof(float), m, 0, NULL, NULL);
    checkCLError(status, "Writing m buffer");

    status = clEnqueueWriteBuffer(commandQueue, a_cuda, CL_TRUE, 0, Size * Size * sizeof(float), a, 0, NULL, NULL);
    checkCLError(status, "Writing a buffer");

    status = clEnqueueWriteBuffer(commandQueue, b_cuda, CL_TRUE, 0, Size * sizeof(float), b, 0, NULL, NULL);
    checkCLError(status, "Writing b buffer");

    // Compile program
    program = clCreateProgramWithSource(context, 1, &kernel_source, NULL, &status);
    checkCLError(status, "Creating program");

    status = clBuildProgram(program, 1, &device, NULL, NULL, NULL);
    if (status != CL_SUCCESS) {
        printf("Build failed\n");
        exit(-1);
    }

    kernelFan1 = clCreateKernel(program, "Fan1", &status);
    checkCLError(status, "Creating Fan1 kernel");

    kernelFan2 = clCreateKernel(program, "Fan2", &status);
    checkCLError(status, "Creating Fan2 kernel");

    int block_size, grid_size;

    block_size = MAXBLOCKSIZE;
    grid_size = (Size/block_size) + (!(Size%block_size)? 0:1);

    size_t globalWorkSize1[1] = {grid_size * block_size};
    size_t localWorkSize1[1] = {block_size};

    int blockSize2d, gridSize2d;
    blockSize2d = BLOCK_SIZE_XY;
