mergeSortFirst(float4 *result, int listsize, const float4 *texData) 
{
    int bx = blockIdx.x;

    int idx = bx*blockDim.x + threadIdx.x;

	if(idx < listsize/4){
		float4 r = texData[idx];
		result[idx] = sortElem(r); 
	}
