	const fp b31 = 1.0 / 36.0;
	const fp b32 = 3.0 / 36.0;
	const fp b41 = 1.0 / 24.0;
	const fp b43 = 3.0 / 24.0;
	const fp b51 = 20.0 / 48.0;
