void kernel(int timeinst,
            fp* d_initvalu,
            fp* d_finavalu,
            fp* d_params,
            fp* d_com){

    int bx;
    int tx;

    int valu_offset;
    int params_offset;
    int com_offset;

    fp CaDyad;
    fp CaSL;
    fp CaCyt;

    bx = 0;
    tx = 0;

    if(bx == 0){
        if(tx == 0){

            valu_offset = 0;

            kernel_ecc(	timeinst,
                                d_initvalu,
                                d_finavalu,
                                valu_offset,
                                d_params);

        }
    }

    else if(bx == 1){
        if(tx == 0){

            valu_offset = 46;
            params_offset = 0;
            com_offset = 0;
            CaDyad = d_initvalu[35]*1e3;

            kernel_cam(	timeinst,
                                    d_initvalu,
                                    d_finavalu,
                                    valu_offset,
                                    d_params,
                                    params_offset,
                                    d_com,
                                    com_offset,
                                    CaDyad);

            valu_offset = 61;
            params_offset = 5;
            com_offset = 1;
            CaSL = d_initvalu[36]*1e3;

            kernel_cam(	timeinst,
                                    d_initvalu,
                                    d_finavalu,
                                    valu_offset,
                                    d_params,
                                    params_offset,
                                    d_com,
                                    com_offset,
                                    CaSL);

            valu_offset = 76;
            params_offset = 10;
            com_offset = 2;
            CaCyt = d_initvalu[37]*1e3;

            kernel_cam(	timeinst,
                                    d_initvalu,
                                    d_finavalu,
                                    valu_offset,
                                    d_params,
                                    params_offset,
                                    d_com,
                                    com_offset,
                                    CaCyt);

        }
    }
}

void kernel_2(int timeinst,
              fp* initvalu,
              fp* params,
              fp* finavalu,
              fp* com){

    int valu_offset_ecc;
    int valu_offset_Dyad;
    int valu_offset_SL;
    int valu_offset_Cyt;

    int params_offset_Dyad;
    int params_offset_SL;
    int params_offset_Cyt;

    int com_offset_Dyad;
    int com_offset_SL;
    int com_offset_Cyt;

    fp CaDyad;
    fp CaSL;
    fp CaCyt;

    int i;

    valu_offset_ecc = 0;
    valu_offset_Dyad = 46;
    valu_offset_SL = 61;
    valu_offset_Cyt = 76;

    params_offset_Dyad = 0;
    params_offset_SL = 5;
    params_offset_Cyt = 10;

    com_offset_Dyad = 0;
    com_offset_SL = 1;
    com_offset_Cyt = 2;

    kernel_ecc_2(	timeinst,
                            initvalu,
                            finavalu,
                            valu_offset_ecc,
                            params);

    CaDyad = initvalu[35]*1e3;

    kernel_cam_2(	timeinst,
                                initvalu,
                                finavalu,
                                valu_offset_Dyad,
                                params,
                                params_offset_Dyad,
                                com,
                                com_offset_Dyad,
                                CaDyad);

    CaSL = initvalu[36]*1e3;

    kernel_cam_2(	timeinst,
                                initvalu,
                                finavalu,
                                valu_offset_SL,
                                params,
                                params_offset_SL,
                                com,
                                com_offset_SL,
                                CaSL);

    CaCyt = initvalu[37]*1e3;

    kernel_cam_2(	timeinst,
                                initvalu,
                                finavalu,
                                valu_offset_Cyt,
                                params,
                                params_offset_Cyt,
                                com,
                                com_offset_Cyt,
                                CaCyt);

    kernel_fin_2(	timeinst,
                            initvalu,
                            finavalu,
                            valu_offset_ecc,
                            valu_offset_Dyad,
                            valu_offset_SL,
                            valu_offset_Cyt,
                            params,
                            com);

    for(i=0; i<EQUATIONS; i++){
        if (isnan(finavalu[i]) == 1){ 
            finavalu[i] = 0.0001;
        }
        else if (isinf(finavalu[i]) == 1){ 
            finavalu[i] = 0.0001;
        }
    }
}

