    d_finavalu[offset_38] = -J_serca-J_CaB_cytosol +J_ca_slmyo/Vmyo*(d_initvalu_37-d_initvalu_38);

    state = 1;
    switch(state){
        case 0:
            I_app = 0;
            break;
        case 1:
            if(fmod(timeinst,cycleLength) <= 5){
                I_app = 9.5;
            }
            else{
                I_app = 0.0;
            }
            break;
        case 2:     
            V_hold = -55;
            V_test = 0;
            if(timeinst>0.5 && timeinst<200.5){
                V_clamp = V_test;
            }
            else{
                V_clamp = V_hold;
            }
            R_clamp = 0.04;
            I_app = (V_clamp-d_initvalu_39)/R_clamp;
            break;
    } 

    I_Na_tot = I_Na_tot_junc + I_Na_tot_sl;
    I_Cl_tot = I_ClCa+I_Clbk;
    I_Ca_tot = I_Ca_tot_junc+I_Ca_tot_sl;
    I_tot = I_Na_tot+I_Cl_tot+I_Ca_tot+I_K_tot;
    d_finavalu[offset_39] = -(I_tot-I_app);

    d_finavalu[offset_41] = 0;
    d_finavalu[offset_42] = 0;
}

void kernel_fin(fp *initvalu,
                int initvalu_offset_ecc,
                int initvalu_offset_Dyad,
                int initvalu_offset_SL,
                int initvalu_offset_Cyt,
                fp *parameter,
                fp *finavalu,
                fp JCaDyad,
                fp JCaSL,
                fp JCaCyt){

    fp BtotDyad;
    fp CaMKIItotDyad;

    fp Vmyo;
    fp Vdyad;
    fp VSL;

    fp kSLmyo;
    fp k0Boff;
    fp k0Bon;
    fp k2Boff;
    fp k2Bon;

    fp k4Bon;
    fp CaMtotDyad;
    fp Bdyad;
    fp J_cam_dyadSL;
    fp J_ca2cam_dyadSL;
    fp J_ca4cam_dyadSL;
    fp J_cam_SLmyo;
    fp J_ca2cam_SLmyo;
    fp J_ca4cam_SLmyo;

    BtotDyad      = parameter[2];
    CaMKIItotDyad = parameter[3];

    Vmyo = 2.1454e-11;
    Vdyad = 1.7790e-14;
    VSL = 6.6013e-13;

    kSLmyo = 8.587e-15;
    k0Boff = 0.0014;
    k0Bon = k0Boff/0.2;
    k2Boff = k0Boff/100;
    k2Bon = k0Bon;

    k4Bon = k0Bon;

    finavalu[initvalu_offset_ecc+35] = finavalu[initvalu_offset_ecc+35] + 1e-3*JCaDyad;
    finavalu[initvalu_offset_ecc+36] = finavalu[initvalu_offset_ecc+36] + 1e-3*JCaSL;
    finavalu[initvalu_offset_ecc+37] = finavalu[initvalu_offset_ecc+37] + 1e-3*JCaCyt; 

    CaMtotDyad = initvalu[initvalu_offset_Dyad+0]
               + initvalu[initvalu_offset_Dyad+1]
               + initvalu[initvalu_offset_Dyad+2]
               + initvalu[initvalu_offset_Dyad+3]
               + initvalu[initvalu_offset_Dyad+4]
               + initvalu[initvalu_offset_Dyad+5]
               + CaMKIItotDyad * (  initvalu[initvalu_offset_Dyad+6]
                                  + initvalu[initvalu_offset_Dyad+7]
                                  + initvalu[initvalu_offset_Dyad+8]
                                  + initvalu[initvalu_offset_Dyad+9])
               + initvalu[initvalu_offset_Dyad+12]
               + initvalu[initvalu_offset_Dyad+13]
               + initvalu[initvalu_offset_Dyad+14];
    Bdyad = BtotDyad - CaMtotDyad;
    J_cam_dyadSL = 1e-3 * (  k0Boff*initvalu[initvalu_offset_Dyad+0] - k0Bon*Bdyad*initvalu[initvalu_offset_SL+0]);
    J_ca2cam_dyadSL = 1e-3 * (  k2Boff*initvalu[initvalu_offset_Dyad+1] - k2Bon*Bdyad*initvalu[initvalu_offset_SL+1]);
    J_ca4cam_dyadSL = 1e-3 * (  k2Boff*initvalu[initvalu_offset_Dyad+2] - k4Bon*Bdyad*initvalu[initvalu_offset_SL+2]);

    J_cam_SLmyo = kSLmyo * (  initvalu[initvalu_offset_SL+0] - initvalu[initvalu_offset_Cyt+0]);
    J_ca2cam_SLmyo = kSLmyo * (  initvalu[initvalu_offset_SL+1] - initvalu[initvalu_offset_Cyt+1]);
    J_ca4cam_SLmyo = kSLmyo * (  initvalu[initvalu_offset_SL+2] - initvalu[initvalu_offset_Cyt+2]);

    finavalu[initvalu_offset_Dyad+0] = finavalu[initvalu_offset_Dyad+0] - J_cam_dyadSL;
    finavalu[initvalu_offset_Dyad+1] = finavalu[initvalu_offset_Dyad+1] - J_ca2cam_dyadSL;
    finavalu[initvalu_offset_Dyad+2] = finavalu[initvalu_offset_Dyad+2] - J_ca4cam_dyadSL;

    finavalu[initvalu_offset_SL+0] = finavalu[initvalu_offset_SL+0] + J_cam_dyadSL*Vdyad/VSL - J_cam_SLmyo/VSL;
    finavalu[initvalu_offset_SL+1] = finavalu[initvalu_offset_SL+1] + J_ca2cam_dyadSL*Vdyad/VSL - J_ca2cam_SLmyo/VSL;
    finavalu[initvalu_offset_SL+2] = finavalu[initvalu_offset_SL+2] + J_ca4cam_dyadSL*Vdyad/VSL - J_ca4cam_SLmyo/VSL;

    finavalu[initvalu_offset_Cyt+0] = finavalu[initvalu_offset_Cyt+0] + J_cam_SLmyo/Vmyo;
    finavalu[initvalu_offset_Cyt+1] = finavalu[initvalu_offset_Cyt+1] + J_ca2cam_SLmyo/Vmyo;
    finavalu[initvalu_offset_Cyt+2] = finavalu[initvalu_offset_Cyt+2] + J_ca4cam_SLmyo/Vmyo;
}

void kernel_fin_2(int timeinst,
                  fp* d_initvalu,
                  fp* d_finavalu,
                  int offset_ecc,
                  int offset_Dyad,
                  int offset_SL,
                  int offset_Cyt,
                  fp* d_params,
                  fp* d_com){

    fp BtotDyad;
    fp CaMKIItotDyad;

    fp Vmyo;
    fp Vdyad;
    fp VSL;

    fp kSLmyo;
    fp k0Boff;
    fp k0Bon;
    fp k2Boff;
    fp k2Bon;

    fp k4Bon;
    fp CaMtotDyad;
    fp Bdyad;
    fp J_cam_dyadSL;
    fp J_ca2cam_dyadSL;
    fp J_ca4cam_dyadSL;
    fp J_cam_SLmyo;
    fp J_ca2cam_SLmyo;
    fp J_ca4cam_SLmyo;

    BtotDyad = d_params[1];
    CaMKIItotDyad = d_params[2];

    d_finavalu[offset_ecc+35] = d_finavalu[offset_ecc+35] + 1e-3*d_com[0];
    d_finavalu[offset_ecc+36] = d_finavalu[offset_ecc+36] + 1e-3*d_com[1];
    d_finavalu[offset_ecc+37] = d_finavalu[offset_ecc+37] + 1e-3*d_com[2]; 

    Vmyo = 2.1454e-11;
    Vdyad = 1.7790e-14;
    VSL = 6.6013e-13;

    kSLmyo = 8.587e-15;
    k0Boff = 0.0014;
    k0Bon = k0Boff/0.2;
    k2Boff = k0Boff/100;
    k2Bon = k0Bon;

    k4Bon = k0Bon;
    CaMtotDyad = d_initvalu[offset_Dyad+0]
               + d_initvalu[offset_Dyad+1]
               + d_initvalu[offset_Dyad+2]
               + d_initvalu[offset_Dyad+3]
               + d_initvalu[offset_Dyad+4]
               + d_initvalu[offset_Dyad+5]
               + CaMKIItotDyad * (	  d_initvalu[offset_Dyad+6]
                                                  + d_initvalu[offset_Dyad+7]
                                                  + d_initvalu[offset_Dyad+8]
                                                  + d_initvalu[offset_Dyad+9])
               + d_initvalu[offset_Dyad+12]
               + d_initvalu[offset_Dyad+13]
               + d_initvalu[offset_Dyad+14];
    Bdyad = BtotDyad - CaMtotDyad;
    J_cam_dyadSL = 1e-3 * (  k0Boff*d_initvalu[offset_Dyad+0] - k0Bon*Bdyad*d_initvalu[offset_SL+0]);
    J_ca2cam_dyadSL = 1e-3 * (  k2Boff*d_initvalu[offset_Dyad+1] - k2Bon*Bdyad*d_initvalu[offset_SL+1]);
    J_ca4cam_dyadSL = 1e-3 * (  k2Boff*d_initvalu[offset_Dyad+2] - k4Bon*Bdyad*d_initvalu[offset_SL+2]);

    J_cam_SLmyo = kSLmyo * (  d_initvalu[offset_SL+0] - d_initvalu[offset_Cyt+0]);
    J_ca2cam_SLmyo = kSLmyo * (  d_initvalu[offset_SL+1] - d_initvalu[offset_Cyt+1]);
    J_ca4cam_SLmyo = kSLmyo * (  d_initvalu[offset_SL+2] - d_initvalu[offset_Cyt+2]);

    d_finavalu[offset_Dyad+0] = d_finavalu[offset_Dyad+0] - J_cam_dyadSL;
    d_finavalu[offset_Dyad+1] = d_finavalu[offset_Dyad+1] - J_ca2cam_dyadSL;
    d_finavalu[offset_Dyad+2] = d_finavalu[offset_Dyad+2] - J_ca4cam_dyadSL;

    d_finavalu[offset_SL+0] = d_finavalu[offset_SL+0] + J_cam_dyadSL*Vdyad/VSL - J_cam_SLmyo/VSL;
    d_finavalu[offset_SL+1] = d_finavalu[offset_SL+1] + J_ca2cam_dyadSL*Vdyad/VSL - J_ca2cam_SLmyo/VSL;
    d_finavalu[offset_SL+2] = d_finavalu[offset_SL+2] + J_ca4cam_dyadSL*Vdyad/VSL - J_ca4cam_SLmyo/VSL;

    d_finavalu[offset_Cyt+0] = d_finavalu[offset_Cyt+0] + J_cam_SLmyo/Vmyo;
    d_finavalu[offset_Cyt+1] = d_finavalu[offset_Cyt+1] + J_ca2cam_SLmyo/Vmyo;
    d_finavalu[offset_Cyt+2] = d_finavalu[offset_Cyt+2] + J_ca4cam_SLmyo/Vmyo;
}

void kernel_2(int timeinst,
              fp* initvalu,
              fp* params,
              fp* finavalu,
              fp* com){

    int valu_offset_ecc;
    int valu_offset_Dyad;
    int valu_offset_SL;
    int valu_offset_Cyt;

    int params_offset_Dyad;
    int params_offset_SL;
    int params_offset_Cyt;

    int com_offset_Dyad;
    int com_offset_SL;
    int com_offset_Cyt;

    fp CaDyad;
    fp CaSL;
    fp CaCyt;

    int i;

    valu_offset_ecc = 0;
    valu_offset_Dyad = 46;
    valu_offset_SL = 61;
    valu_offset_Cyt = 76;

    params_offset_Dyad = 0;
    params_offset_SL = 5;
    params_offset_Cyt = 10;

    com_offset_Dyad = 0;
    com_offset_SL = 1;
    com_offset_Cyt = 2;

    kernel_ecc_2(	timeinst,
                            initvalu,
                            finavalu,
                            valu_offset_ecc,
                            params);

    CaDyad = initvalu[35]*1e3;

    kernel_cam_2(	timeinst,
                                initvalu,
                                finavalu,
                                valu_offset_Dyad,
                                params,
                                params_offset_Dyad,
                                com,
                                com_offset_Dyad,
                                CaDyad);

    CaSL = initvalu[36]*1e3;

    kernel_cam_2(	timeinst,
                                initvalu,
                                finavalu,
                                valu_offset_SL,
                                params,
                                params_offset_SL,
                                com,
                                com_offset_SL,
                                CaSL);

    CaCyt = initvalu[37]*1e3;

    kernel_cam_2(	timeinst,
                                initvalu,
                                finavalu,
                                valu_offset_Cyt,
                                params,
                                params_offset_Cyt,
                                com,
                                com_offset_Cyt,
                                CaCyt);

    kernel_fin_2(	timeinst,
                            initvalu,
                            finavalu,
                            valu_offset_ecc,
                            valu_offset_Dyad,
                            valu_offset_SL,
                            valu_offset_Cyt,
                            params,
                            com);

    for(i=0; i<EQUATIONS; i++){
        if (isnan(finavalu[i]) == 1){ 
            finavalu[i] = 0.0001;
        }
        else if (isinf(finavalu[i]) == 1){ 
            finavalu[i] = 0.0001;
        }
    }
}

void solver_2(int workload,
              int xmax,
              fp* x,
              fp* y,
              fp* params,
              fp* com,
              fp* err,
              fp* scale,
              fp* yy,
              fp* initvalu_temp,
              fp* finavalu_temp){

    int bx;
    int tx;
    int tid;

    long y_pointer_initial;
    long y_pointer_current; 
    long x_pointer_current;
    int err_pointer;
    int scale_pointer;
    int yy_pointer;
    int params_pointer;
    int initvalu_temp_pointer;
    int finavalu_temp_pointer;
    int com_pointer;

    fp err_exponent ;
    fp h_init;
    fp h;
    fp tolerance;
    int xmin;

    int error;
    int outside;
    fp scale_min;
    fp scale_fina;

    int i, j, k;

    bx = 0;
    tx = 0;
    tid = bx*NUMBER_THREADS+tx;

    err_pointer = tid*EQUATIONS;
    scale_pointer = tid*EQUATIONS;
    yy_pointer = tid*EQUATIONS;
    params_pointer = tid*PARAMETERS;
    initvalu_temp_pointer = tid*EQUATIONS;
    finavalu_temp_pointer = tid*13*EQUATIONS;
    com_pointer = tid*3;

    err_exponent = 1.0 / 7.0;
    h_init = 1;
    h = h_init;
    xmin = 0;
    tolerance = 10 / (fp)(xmax - xmin);

    if (xmax < xmin || h <= 0.0){
        return;
    }

    if (xmax == xmin){
        return; 
    }

    if (h > (xmax - xmin) ) { 
        h = (fp)xmax - (fp)xmin; 
    }

    if(tid<workload){

        for(k=1; k<(xmax+1); k++) {

            y_pointer_initial = tid*((xmax+1)*EQUATIONS)+(k-1)*EQUATIONS;
            y_pointer_current = tid*((xmax+1)*EQUATIONS)+k*EQUATIONS;
            x_pointer_current = tid*(xmax+1)+k;

            x[x_pointer_current] = (fp)k;
            h = h_init;

            scale_fina = 1.0;

            for (j = 0; j < ATTEMPTS; j++) {

                error = 0;
                outside = 0;
                scale_min = MAX_SCALE_FACTOR;

                embedded_fehlberg_7_8_2(	h,

                                                                x[x_pointer_current],
                                                                &y[y_pointer_initial],
                                                                &y[y_pointer_current],
                                                                &params[params_pointer],

                                                                &err[err_pointer],
                                                                &initvalu_temp[initvalu_temp_pointer],
                                                                &finavalu_temp[finavalu_temp_pointer],
                                                                &com[com_pointer]);

                for(i=0; i<EQUATIONS; i++){
                    if(err[err_pointer+i] > 0){
                        error = 1;
                    }
                }
                if (error != 1) {
                    scale_fina = MAX_SCALE_FACTOR; 
                    break;
                }

                for(i=0; i<EQUATIONS; i++){
                    if(y[y_pointer_initial+i] == 0.0){
                        yy[yy_pointer+i] = tolerance;
                    }
                    else{
                        yy[yy_pointer+i] = fabs(y[y_pointer_initial+i]);
                    }
                    scale[scale_pointer+i] = 0.8 * pow( tolerance * yy[yy_pointer+i] / err[err_pointer+i] , err_exponent );
                    if(scale[scale_pointer+i]<scale_min){
                        scale_min = scale[scale_pointer+i];
                    }
                }
                scale_fina = min( max(scale_min,MIN_SCALE_FACTOR), MAX_SCALE_FACTOR);

                for(i=0; i<EQUATIONS; i++){
                    if ( err[err_pointer+i] > ( tolerance * yy[yy_pointer+i] ) ){
                        outside = 1;
                    }
                }
                if (outside == 0){
                    break;
                }

                h = h * scale_fina;

                if (h >= 0.9) {
                    h = 0.9;
                }

                if ( x[x_pointer_current] + h > (fp)xmax ){
                    h = (fp)xmax - x[x_pointer_current];
                }

                else if ( x[x_pointer_current] + h + 0.5 * h > (fp)xmax ){
                    h = 0.5 * h;
                }

            }

            x[x_pointer_current] = x[x_pointer_current] + h;

            if ( j >= ATTEMPTS ) {
                return; 
            }

        }

    }

    return;
}

