#pragma OPENCL EXTENSION cl_khr_fp64 : enable

typedef struct latLong
{
  float lat;
  float lng;
} LatLong;

typedef struct record
{
  char recString[53];
  float distance;
} Record;

__kernel void euclid(__global LatLong *d_locations, __global float *d_distances, int numRecords, float lat, float lng)
{
    int globalId = get_global_id(0);

    if (globalId < numRecords) {
        LatLong loc = d_locations[globalId];
        float diff_lat = lat - loc.lat;
        float diff_lng = lng - loc.lng;
        d_distances[globalId] = sqrt(diff_lat * diff_lat + diff_lng * diff_lng);
    }
}

