#ifdef TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif

    // Calculate grid dimensions similar to CUDA logic
    // In OpenCL, we usually define global size directly, but to mimic CUDA grid/block:
    // threadsPerBlock = 256 (or device max)
    // We need device info to mimic the CUDA calculation exactly

    cl_device_id current_device;
    clGetContextInfo(context, CL_CONTEXT_DEVICES, sizeof(cl_device_id), &current_device, NULL);

    cl_ulong maxMemAlloc;
    clGetDeviceInfo(current_device, CL_DEVICE_MAX_MEM_ALLOC_SIZE, sizeof(cl_ulong), &maxMemAlloc, NULL);

    size_t maxThreadsPerBlock;
    clGetDeviceInfo(current_device, CL_DEVICE_MAX_WORK_GROUP_SIZE, sizeof(size_t), &maxThreadsPerBlock, NULL);

    size_t threadsPerBlock = min((unsigned long)maxThreadsPerBlock, (unsigned long)DEFAULT_THREADS_PER_BLOCK);

    // Mimic CUDA memory check (approximate)
    // CUDA used freeDeviceMemory * 0.85 / 12
    // OpenCL max_mem_alloc is a hard limit per object usually.
    // We'll stick to the thread count logic primarily.

    unsigned long maxThreads = numRecords; // Simplified for OpenCL, usually memory is sufficient if allocation succeeded

    if ( numRecords > maxThreads ) // This check in CUDA was based on specific memory calc, we assume success if alloc worked
    {
