const char* euclid_kernel_source = 
"typedef struct latLong { float lat; float lng; } LatLong;\n"
"\n"
"__kernel void euclid(__global LatLong *d_locations, __global float *d_distances, int numRecords, float lat, float lng) {\n"
"    int globalId = get_global_size(0) * get_global_id(1) + get_global_id(0);\n"
"    // Correction for 2D mapping to match CUDA logic: \n"
"    // CUDA: globalId = blockDim.x * (gridDim.x * blockIdx.y + blockIdx.x) + threadIdx.x\n"
"    // OpenCL 2D: global_id(0) is x, global_id(1) is y.\n"
"    // Global size X = gridX * threadsPerBlock, Global size Y = gridY.\n"
"    // Block index X = global_id(0) / threadsPerBlock\n"
"    // Block index Y = global_id(1)\n"
"    // Local index X = global_id(0) % threadsPerBlock\n"
"    // Reconstructing CUDA globalId:\n"
"    int threadsPerBlock = get_local_size(0);\n"
"    int blockIdx_x = get_global_id(0) / threadsPerBlock;\n"
"    int blockIdx_y = get_global_id(1);\n"
"    int threadIdx_x = get_global_id(0) % threadsPerBlock;\n"
"    int gridDim_x = get_global_size(0) / threadsPerBlock;\n"
"    \n"
"    int cudaGlobalId = threadsPerBlock * (gridDim_x * blockIdx_y + blockIdx_x) + threadIdx_x;\n"
"    \n"
"    if (cudaGlobalId < numRecords) {\n"
"        float d_lat = lat - d_locations[cudaGlobalId].lat;\n"
"        float d_lng = lng - d_locations[cudaGlobalId].lng;\n"
"        d_distances[cudaGlobalId] = sqrt(d_lat*d_lat + d_lng*d_lng);\n"
"    }\n"
"}\n";

// Redefining main to use embedded kernel
int main_embedded(int argc, char* argv[])
{
    int    i=0;
    float lat, lng;
    int quiet=0,timing=0,platform=0,device=0;

    std::vector<Record> records;
    std::vector<LatLong> locations;
    char filename[100];
    int resultsCount=10;

    if (parseCommandline(argc, argv, filename,&resultsCount,&lat,&lng,
                         &quiet, &timing, &platform, &device)) {
        printUsage();
        return 0;
    }

    int numRecords = loadData(filename,records,locations);
    if (resultsCount > numRecords) resultsCount = numRecords;

    cl_context context = cl_init_context(platform, device, quiet);

    float *distances = (float *)malloc(sizeof(float) * numRecords);

    cl_mem d_locations = cl_allocBuffer(sizeof(LatLong) * numRecords, CL_MEM_READ_WRITE);
    cl_mem d_distances = cl_allocBuffer(sizeof(float) * numRecords, CL_MEM_READ_WRITE);

    cl_copyBufferToDevice(d_locations, &locations[0], sizeof(LatLong) * numRecords, CL_TRUE);

    cl_int status;
    cl_program program = clCreateProgramWithSource(context, 1, &euclid_kernel_source, NULL, &status);
    if (cl_errChk(status, "Creating program", true)) exit(1);

    status = clBuildProgram(program, 0, NULL, NULL, NULL, NULL);
    if (cl_errChk(status, "Building program", true)) exit(1);

    cl_kernel kernel = clCreateKernel(program, "euclid", &status);
    if (cl_errChk(status, "Creating kernel", true)) exit(1);

#ifdef TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif

    // Calculate grid dimensions
    cl_device_id current_device;
    clGetContextInfo(context, CL_CONTEXT_DEVICES, sizeof(cl_device_id), &current_device, NULL);

    size_t maxThreadsPerBlock;
    clGetDeviceInfo(current_device, CL_DEVICE_MAX_WORK_GROUP_SIZE, sizeof(size_t), &maxThreadsPerBlock, NULL);

    size_t threadsPerBlock = min((unsigned long)maxThreadsPerBlock, (unsigned long)DEFAULT_THREADS_PER_BLOCK);

    unsigned long blocks = ceilDiv( numRecords, threadsPerBlock );
    unsigned long maxGridX = 65535; 
    unsigned long gridY = ceilDiv( blocks, maxGridX );
    unsigned long gridX = ceilDiv( blocks, gridY );

    size_t global_dims[2] = {(size_t)gridX * threadsPerBlock, (size_t)gridY};
    size_t local_dims[2] = {threadsPerBlock, 1};

    cl_setKernelArg(kernel, 0, sizeof(cl_mem), &d_locations);
    cl_setKernelArg(kernel, 1, sizeof(cl_mem), &d_distances);
    cl_setKernelArg(kernel, 2, sizeof(int), &numRecords);
    cl_setKernelArg(kernel, 3, sizeof(float), &lat);
    cl_setKernelArg(kernel, 4, sizeof(float), &lng);

    cl_event event;
    status = clEnqueueNDRangeKernel(cl_getCommandQueue(), kernel, 2, NULL, global_dims, local_dims, 0, NULL, &event);
    if (cl_errChk(status, "Launching kernel", true)) exit(1);

    cl_sync();

#ifdef TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    cl_copyBufferToHost(distances, d_distances, sizeof(float)*numRecords, CL_TRUE);

    findLowest(records,distances,numRecords,resultsCount);

    if (!quiet)
        for(i=0;i<resultsCount;i++) {
            printf("%s --> Distance=%f\n",records[i].recString,records[i].distance);
        }

    free(distances);

    cl_freeMem(d_locations);
    cl_freeMem(d_distances);
    cl_freeKernel(kernel);
    clReleaseProgram(program);
    cl_cleanup();

#ifdef TIMING
    printf("Exec: %f\n", kernel_time);
#endif
    return 0;
}

