// OpenCL Kernel Definitions
// These kernels correspond to the functionality in Source File 2 and Infrastructure Files 1,2,4,5
// They are required by Infrastructure File 3.

// Define fp if not defined (Infrastructure uses fp)
#ifndef fp
#define fp float
#endif

// Define NUMBER_THREADS if not defined (Infrastructure uses it, Source uses BLOCK_SIZE)
#ifndef NUMBER_THREADS
#define NUMBER_THREADS BLOCK_SIZE
#endif

// Kernel: extract (from Infrastructure File 1)
__kernel void extract_kernel(
    long d_Ne,
    fp *d_I)
{
    int bx = get_block_id(0);
    int tx = get_thread_id(0);
    int ei = (bx * NUMBER_THREADS) + tx;

    if (ei < d_Ne) {
        d_I[ei] = log(d_I[ei]) * 255;
    }
}

// Kernel: compress (from Infrastructure File 2 - named compress in file, but wrapper expects compress_kernel)
__kernel void compress_kernel(
    long d_Ne,
    fp *d_I)
{
    int bx = get_block_id(0);
    int tx = get_thread_id(0);
    int ei = (bx * NUMBER_THREADS) + tx;

    if (ei < d_Ne) {
        d_I[ei] = exp(d_I[ei] / 255);
    }
}

// Kernel: prepare (from Infrastructure File 4 - wrapper expects prepare_kernel)
__kernel void prepare_kernel(
    long d_Ne,
    fp *d_I,
    fp *d_sums,
    fp *d_sums2)
{
    int bx = get_block_id(0);
    int tx = get_thread_id(0);
    int ei = (bx * NUMBER_THREADS) + tx;

    if (ei < d_Ne) {
        d_sums[ei] = d_I[ei];
        d_sums2[ei] = d_I[ei] * d_I[ei];
    }
}

// Kernel: reduce (from Infrastructure File 5 - wrapper expects reduce_kernel)
__kernel void reduce_kernel(
    long d_Ne,
    long d_no,
    int d_mul,
    fp *d_sums,
    fp *d_sums2,
    int blocks2_work_size) // Added argument as per Infrastructure File 3 usage (argument 5)
{
    int bx = get_block_id(0);
    int tx = get_thread_id(0);
    int ei = (bx * NUMBER_THREADS) + tx;
    int nf = NUMBER_THREADS - (get_num_blocks(0) * NUMBER_THREADS - d_no);
    int df = 0;

    __local fp d_psum[NUMBER_THREADS];
    __local fp d_psum2[NUMBER_THREADS];

    int i;

    if (ei < d_no) {
        d_psum[tx] = d_sums[ei * d_mul];
        d_psum2[tx] = d_sums2[ei * d_mul];
    }

    if (nf == NUMBER_THREADS) {
        for (i = 2; i <= NUMBER_THREADS; i = 2 * i) {
            if ((tx + 1) % i == 0) {
                d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
            }
            barrier(CLK_LOCAL_MEM_FENCE);
        }

        if (tx == (NUMBER_THREADS - 1)) {
            d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[tx];
            d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[tx];
        }
    } else {
        if (bx != (get_num_blocks(0) - 1)) {
            for (i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                if ((tx + 1) % i == 0) {
                    d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                    d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                }
                barrier(CLK_LOCAL_MEM_FENCE);
            }

            if (tx == (NUMBER_THREADS - 1)) {
                d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[tx];
                d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[tx];
            }
        } else {
            for (i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                if (nf >= i) {
                    df = i;
                }
            }

            for (i = 2; i <= df; i = 2 * i) {
                if ((tx + 1) % i == 0 && tx < df) {
                    d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                    d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                }
                barrier(CLK_LOCAL_MEM_FENCE);
            }

            if (tx == (df - 1)) {
                for (i = (bx * NUMBER_THREADS) + df; i < (bx * NUMBER_THREADS) + nf; i++) {
                    d_psum[tx] = d_psum[tx] + d_sums[i];
                    d_psum2[tx] = d_psum2[tx] + d_sums2[i];
                }
                d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[tx];
                d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[tx];
            }
        }
    }
}

// Helper macros for OpenCL thread/block indexing to mimic CUDA
#define get_block_id(dim) get_group_id(dim)
#define get_thread_id(dim) get_local_id(dim)
#define get_num_blocks(dim) get_num_groups(dim)

// Kernel: srad_kernel (Translated from Source File 2: srad_cuda_1)
__kernel void srad_kernel(
    fp lambda,
    int rows,
    int cols,
    long Ne,
    const int *iN,
    const int *iS,
    const int *jE,
    const int *jW,
    fp *d_dN,
    fp *d_dS,
    fp *d_dW,
    fp *d_dE,
    fp q0sqr,
    fp *d_c,
    fp *d_I)
{
    int bx = get_block_id(0);
    int by = get_block_id(1);
    int tx = get_thread_id(0);
    int ty = get_thread_id(1);

    // Calculate global index
    int index = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * ty + tx;

    // Boundary checks for global index
    if (index >= Ne) return;

    // Use the precomputed neighbor indices from host (CPU approach mapped to GPU)
    // Or compute on fly? The infrastructure passes iN, iS, jE, jW.
    // Let's use the passed arrays for consistency with infrastructure.
    int row = index / cols;
    int col = index % cols;

    int idx_n = iN[row] * cols + col;
    int idx_s = iS[row] * cols + col;
    int idx_w = row * cols + jW[col];
    int idx_e = row * cols + jE[col];

    fp jc = d_I[index];
    fp n_val = d_I[idx_n];
    fp s_val = d_I[idx_s];
    fp w_val = d_I[idx_w];
    fp e_val = d_I[idx_e];

    fp dN = n_val - jc;
    fp dS = s_val - jc;
    fp dW = w_val - jc;
    fp dE = e_val - jc;

    // Store differences
    d_dN[index] = dN;
    d_dS[index] = dS;
